
'use strict';
const APP_VERSION='8.2.3';
const STORAGE_KEY='audv815';
const SECTIONS=[{"id": "ethics", "roman": "I", "name": "Ethics, Professional Responsibilities & General Principles", "weight": "15\u201325%"}, {"id": "risk", "roman": "II", "name": "Assessing Risk & Developing a Planned Response", "weight": "25\u201335%"}, {"id": "evidence", "roman": "III", "name": "Performing Further Procedures & Obtaining Evidence", "weight": "30\u201340%"}, {"id": "reporting", "roman": "IV", "name": "Forming Conclusions & Reporting", "weight": "10\u201320%"}];
const QUESTIONS=[{"id":"ethics-001","sec":"ethics","topic":"Independence","conceptId":"ethics-independence-001","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A senior audit manager discovers her spouse accepted a controller position at the audit client before fieldwork begins. What should the firm do before continuing the engagement?","choices":["Continue because the spouse is not preparing the audit report.","Document the relationship only after the report is issued.","Proceed if the client signs a consent letter.","Evaluate and eliminate the independence threat, such as removing the covered member from the engagement, before continuing."],"ans":"D","exp":"Independence requires both fact and appearance; client consent alone does not cure a covered-member threat."},{"id":"ethics-011","sec":"ethics","topic":"Independence","conceptId":"ethics-independence-011","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The engagement partner learns that an engagement team member has a close family member in a key financial reporting role at the client. Which response best protects independence?","choices":["Remove the team member from the engagement or otherwise eliminate/reduce the threat to an acceptable level before continuing.","Continue if the client signs a representation acknowledging the relationship.","Document the matter after report release only if a misstatement is found.","Assign the team member only to planning because planning is not an attest service."],"ans":"A","exp":"Independence requires both fact and appearance; client consent alone does not cure a covered-member threat."},{"id":"ethics-002","sec":"ethics","topic":"Nonaudit services","conceptId":"ethics-nonaudit-services-002","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"An audit client asks the firm to prepare journal entries and post them to the general ledger. Which condition is necessary if the firm assists with bookkeeping?","choices":["The auditor may approve the entries as long as they are immaterial.","The auditor may post entries and later audit them if fees are disclosed.","The service is always prohibited for all attest clients.","Client management must review, approve, and accept responsibility for the work and the firm must avoid management functions."],"ans":"D","exp":"Permitted nonaudit services cannot place the auditor in a management role or impair independence."},{"id":"ethics-012","sec":"ethics","topic":"Nonaudit services","conceptId":"ethics-nonaudit-services-012","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The audit client asks the firm to prepare depreciation schedules and also decide which fixed assets should be capitalized. Which part of the request creates the independence problem?","choices":["Preparing a schedule based on client-approved assumptions.","Deciding which assets to capitalize because that is a management responsibility.","Providing a template for management to complete.","Explaining the applicable accounting guidance to management."],"ans":"B","exp":"Permitted nonaudit services cannot place the auditor in a management role or impair independence."},{"id":"ethics-003","sec":"ethics","topic":"Engagement acceptance","conceptId":"ethics-engagement-acceptance-003","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Before accepting a new audit, management refuses permission to contact the predecessor auditor. What is the best response?","choices":["Accept the engagement and increase substantive testing.","Contact the predecessor anyway because permission is not needed.","Consider the refusal a red flag about management integrity and ordinarily decline the engagement.","Issue a disclaimer before performing the audit."],"ans":"C","exp":"Predecessor communication helps assess management integrity and acceptance risk."},{"id":"ethics-013","sec":"ethics","topic":"Engagement acceptance","conceptId":"ethics-engagement-acceptance-013","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A prospective client permits contact with the predecessor auditor, who reports repeated disputes over audit adjustments and unpaid fees. What should the successor auditor do next?","choices":["Ignore the information because predecessor comments are not audit evidence.","Accept the engagement and address all issues after fieldwork.","Evaluate management integrity and acceptance risk before deciding whether to accept.","Issue a qualified opinion before beginning the audit."],"ans":"C","exp":"Predecessor communication helps assess management integrity and acceptance risk."},{"id":"ethics-004","sec":"ethics","topic":"Audit documentation","conceptId":"ethics-audit-documentation-004","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A reviewer cannot determine who performed a cash cutoff test, when it was performed, or what conclusion was reached. What is the primary problem?","choices":["The evidence is automatically persuasive because cash was tested.","The audit documentation is insufficient because it does not show work performed, timing, reviewer evidence, and conclusion.","The issue matters only if a misstatement was found.","Documentation can be completed orally after report release."],"ans":"B","exp":"Workpapers must allow an experienced auditor to understand procedures, evidence, timing, and conclusions."},{"id":"ethics-014","sec":"ethics","topic":"Audit documentation","conceptId":"ethics-audit-documentation-014","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"An audit workpaper lists procedures performed but omits the population tested, sample selected, exceptions found, and conclusion. What is the best reviewer response?","choices":["Accept the workpaper because a procedure name is enough.","Require documentation sufficient for an experienced auditor to understand the work and conclusion.","Delete the workpaper to avoid contradictory evidence.","Rely on oral explanation from the preparer after report release."],"ans":"B","exp":"Workpapers must allow an experienced auditor to understand procedures, evidence, timing, and conclusions."},{"id":"ethics-005","sec":"ethics","topic":"Professional skepticism","conceptId":"ethics-professional-skepticism-005","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Inventory margins improved sharply even though industry demand declined. Management says the change is due to better purchasing but provides no support. What should the auditor do?","choices":["Perform additional procedures and corroborate management explanations with evidence.","Rely on the representation letter as the only evidence.","Accept the explanation if management is experienced.","Reduce testing because improved margins lower audit risk."],"ans":"A","exp":"Professional skepticism requires a questioning mind when explanations conflict with other evidence."},{"id":"ethics-015","sec":"ethics","topic":"Professional skepticism","conceptId":"ethics-professional-skepticism-015","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management explains an unusual year-end margin increase by saying “purchasing negotiated better prices,” but no purchase contracts or vendor credits support the claim. What should the auditor do?","choices":["Corroborate management’s explanation with additional audit evidence.","Treat the explanation as sufficient because management is responsible for the statements.","Reduce substantive testing because the margin improved.","Wait until the representation letter is signed and perform no further work."],"ans":"A","exp":"Professional skepticism requires a questioning mind when explanations conflict with other evidence."},{"id":"ethics-006","sec":"ethics","topic":"Quality management","conceptId":"ethics-quality-management-006","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A firm assigns a complex public-company engagement to staff without industry experience or supervision. Which quality management element is most directly affected?","choices":["Reporting only, because quality is assessed at report release.","Resources and engagement performance, because the firm must assign competent personnel and provide supervision/review.","Client acceptance only, because staffing is decided after acceptance.","Independence only, because competence is not a quality matter."],"ans":"B","exp":"Quality management includes competence, supervision, review, and engagement performance."},{"id":"ethics-016","sec":"ethics","topic":"Quality management","conceptId":"ethics-quality-management-016","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A firm accepts a specialized audit but assigns staff with no relevant industry experience and minimal supervision. Which quality management concern is most direct?","choices":["The firm may not have assigned appropriate resources or supervised the engagement adequately.","The audit report must automatically be adverse.","Independence is impaired solely because staff are inexperienced.","Client acceptance is the only quality management element affected."],"ans":"A","exp":"Quality management includes competence, supervision, review, and engagement performance."},{"id":"ethics-007","sec":"ethics","topic":"Due care","conceptId":"ethics-due-care-007","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"An assistant completes high-risk revenue testing without review because the deadline is tight. Which principle is most directly violated?","choices":["Materiality, because revenue is usually large.","Due professional care, including proper planning, supervision, and review.","Independence, because the assistant prepared the schedule.","Confidentiality, because revenue information is private."],"ans":"B","exp":"Due care requires diligent performance and appropriate supervision regardless of deadline pressure."},{"id":"ethics-017","sec":"ethics","topic":"Due care","conceptId":"ethics-due-care-017","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"An auditor signs off on revenue testing without resolving known exceptions because the deadline is approaching. Which principle is most directly violated?","choices":["Due professional care and adequate performance of the engagement.","Confidentiality, because deadlines are private.","Independence, only if fees are unpaid.","Materiality, because deadlines determine audit scope."],"ans":"A","exp":"Due care requires diligent performance and appropriate supervision regardless of deadline pressure."},{"id":"ethics-008","sec":"ethics","topic":"Confidentiality","conceptId":"ethics-confidentiality-008","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A third party asks the auditor for client payroll records without client consent or legal process. What should the auditor do?","choices":["Provide only immaterial records.","Refuse disclosure unless client consent or a professional/legal duty permits it.","Provide the records if no audit opinion has been issued.","Disclose the records because payroll is not part of the audit report."],"ans":"B","exp":"Client information is confidential unless an exception applies."},{"id":"ethics-018","sec":"ethics","topic":"Confidentiality","conceptId":"ethics-confidentiality-018","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A staff auditor wants to discuss a client’s pending acquisition with a friend who invests in the industry. Which response is appropriate?","choices":["Discuss it only if the friend promises not to trade.","Disclose the information after the audit report is issued.","Do not disclose confidential client information without proper authority.","Share only the facts that are already in the audit file."],"ans":"C","exp":"Client information is confidential unless an exception applies."},{"id":"ethics-009","sec":"ethics","topic":"Governance communication","conceptId":"ethics-governance-communication-009","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"During the audit, the team identifies a material weakness in controls over cash disbursements. Who should receive written communication?","choices":["Management and those charged with governance.","No one unless a material misstatement is detected.","Only the external users with the audit report.","Only the accounts payable clerk."],"ans":"A","exp":"Significant deficiencies and material weaknesses are communicated in writing to management and governance."},{"id":"ethics-019","sec":"ethics","topic":"Governance communication","conceptId":"ethics-governance-communication-019","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"During the audit, the team identifies a significant deficiency and an uncorrected misstatement near materiality. Who should receive timely communication?","choices":["Those charged with governance, with appropriate detail about the matters identified.","Only the accounts payable clerk because the audit is operational.","No one until the next year’s planning meeting.","Only external users through an emphasis paragraph."],"ans":"A","exp":"Significant deficiencies and material weaknesses are communicated in writing to management and governance."},{"id":"ethics-010","sec":"ethics","topic":"Engagement letters","conceptId":"ethics-engagement-letters-010","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A prospective client believes management is not responsible for internal control because the auditor will test controls. What should the engagement letter clarify?","choices":["The engagement letter replaces all required audit evidence.","The auditor guarantees detection of all fraud.","The auditor prepares the financial statements as management.","Management is responsible for the financial statements, internal control, and providing access to information."],"ans":"D","exp":"Engagement terms clarify management and auditor responsibilities before work begins."},{"id":"ethics-020","sec":"ethics","topic":"Engagement letters","conceptId":"ethics-engagement-letters-020","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The engagement letter does not describe management’s responsibility for internal control or the auditor’s objective. Why is this a problem?","choices":["The letter should establish the terms of the engagement, including responsibilities and audit objective.","The report must automatically be withdrawn.","The omission allows the auditor to assume management responsibilities.","Engagement letters are optional when the client is recurring."],"ans":"A","exp":"Engagement terms clarify management and auditor responsibilities before work begins."},{"id":"risk-001","sec":"risk","topic":"Understanding the entity","conceptId":"risk-understanding-the-entity-001","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A manufacturer enters a new subscription-based sales arrangement. What planning step is most appropriate?","choices":["Rely only on last year’s audit program.","Ignore the change until year-end cutoff testing.","Understand the new revenue process and identify related risks of material misstatement.","Treat all new contracts as immaterial until billed."],"ans":"C","exp":"Understanding the entity and its environment drives risk assessment and audit planning."},{"id":"risk-011","sec":"risk","topic":"Understanding the entity","conceptId":"risk-understanding-the-entity-011","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"An auditor is planning a first-year audit of a manufacturer with complex rebate programs. Which procedure best supports understanding the entity?","choices":["Read board minutes, understand revenue processes, and inquire about industry and business risks.","Skip planning because substantive procedures will detect all risks.","Use the prior auditor’s report as the only planning document.","Set materiality after the audit report is drafted."],"ans":"A","exp":"Understanding the entity and its environment drives risk assessment and audit planning."},{"id":"risk-002","sec":"risk","topic":"Internal control","conceptId":"risk-internal-control-002","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor performs a walkthrough of purchase-to-pay and observes the same employee can create vendors and approve payments. What risk is indicated?","choices":["A control design deficiency increasing risk of unauthorized or fictitious disbursements.","Evidence that substantive testing can be reduced without more work.","A reporting-only issue unrelated to audit planning.","A going-concern uncertainty."],"ans":"A","exp":"Walkthroughs help evaluate design and implementation of controls."},{"id":"risk-012","sec":"risk","topic":"Internal control","conceptId":"risk-internal-control-012","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A walkthrough shows that invoices are generated automatically when orders ship, but no one reviews changes to pricing tables. What risk should the auditor consider?","choices":["Pricing-table changes may affect revenue accuracy and require control/testing response.","No risk exists because invoices are automated.","The issue affects only tax compliance, not financial reporting.","The auditor should eliminate all substantive revenue testing."],"ans":"A","exp":"Walkthroughs help evaluate design and implementation of controls."},{"id":"risk-003","sec":"risk","topic":"Risk assessment","conceptId":"risk-risk-assessment-003","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Management uses a complex model to value a material warranty liability. Which assertion-level risk is most likely elevated?","choices":["Presentation of common stock.","Rights and obligations for prepaid insurance.","Valuation and allocation for the warranty estimate.","Existence of cash."],"ans":"C","exp":"Complex estimates commonly increase valuation risk."},{"id":"risk-013","sec":"risk","topic":"Risk assessment","conceptId":"risk-risk-assessment-013","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Preliminary analytics show revenue growth of 32% while cash collections declined and receivables aged. What is the best risk assessment response?","choices":["Identify increased risk of material misstatement and design further procedures responsive to revenue/receivables.","Conclude that higher revenue always lowers audit risk.","Rely exclusively on management’s explanation.","Treat the matter as unrelated to audit planning."],"ans":"A","exp":"Complex estimates commonly increase valuation risk."},{"id":"risk-004","sec":"risk","topic":"Materiality","conceptId":"risk-materiality-004","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The client is close to violating a debt covenant based on current ratio. How may this affect materiality?","choices":["Materiality increases automatically when debt is present.","Materiality must equal a fixed percentage of net income in all audits.","Materiality is irrelevant to planning.","The auditor may set lower materiality because users are sensitive to small misstatements affecting covenants."],"ans":"D","exp":"Materiality is judgment-based and considers users and circumstances."},{"id":"risk-014","sec":"risk","topic":"Materiality","conceptId":"risk-materiality-014","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Planning materiality is set at $900,000. A likely misstatement of $820,000 affects a debt covenant disclosure. What should the auditor consider?","choices":["Quantitative and qualitative factors, including covenant sensitivity.","Only the dollar amount because qualitative factors are irrelevant.","Ignore the item because it is below planning materiality.","Automatically issue an adverse opinion."],"ans":"A","exp":"Materiality is judgment-based and considers users and circumstances."},{"id":"risk-005","sec":"risk","topic":"Fraud risk","conceptId":"risk-fraud-risk-005","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The audit team identifies pressure to meet analyst expectations and unusual manual revenue entries at year-end. What is the appropriate response?","choices":["Skip fraud discussion if prior-year testing was clean.","Reduce audit procedures because revenue entries are manual.","Treat revenue recognition as a fraud risk unless rebutted and perform targeted procedures.","Rely only on management’s representation that revenue is proper."],"ans":"C","exp":"Fraud risk requires skepticism and procedures responsive to identified risks."},{"id":"risk-015","sec":"risk","topic":"Fraud risk","conceptId":"risk-fraud-risk-015","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The sales director can approve manual journal entries to revenue in the last week of the year. Which fraud risk response is most appropriate?","choices":["Test journal entries and revenue cutoff with attention to management override.","Eliminate all revenue testing because approval exists.","Rely only on the representation letter.","Perform no work if revenue increased consistently."],"ans":"A","exp":"Fraud risk requires skepticism and procedures responsive to identified risks."},{"id":"risk-006","sec":"risk","topic":"Analytical procedures","conceptId":"risk-analytical-procedures-006","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Planning analytics show gross margin is far above prior years while sales volume declined. What should the auditor do?","choices":["Develop an expectation, investigate the unexpected relationship, and revise risk assessment as needed.","Use the variance as proof that inventory exists.","Ignore analytics because they are optional in planning.","Conclude the audit evidence is sufficient without inquiry."],"ans":"A","exp":"Analytical procedures are required in planning and help identify unusual relationships."},{"id":"risk-016","sec":"risk","topic":"Analytical procedures","conceptId":"risk-analytical-procedures-016","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Gross margin increased from 29% to 47% in December while units shipped declined. How should analytical procedures affect the audit?","choices":["The unexpected relationship should be investigated and corroborated with evidence.","The trend proves revenue is fairly stated.","Analytics replace all tests of details.","No follow-up is needed if management says pricing improved."],"ans":"A","exp":"Analytical procedures are required in planning and help identify unusual relationships."},{"id":"risk-007","sec":"risk","topic":"IT general controls","conceptId":"risk-it-general-controls-007","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"An automated three-way match is relied on, but programmers can move changes into production without approval. What is the main implication?","choices":["Weak change-management ITGCs may undermine reliance on the automated control.","The automated control is always effective because it is computer-based.","The issue is unrelated to financial reporting.","Only physical inventory testing is affected."],"ans":"A","exp":"ITGCs support the reliability of automated controls and reports."},{"id":"risk-017","sec":"risk","topic":"IT general controls","conceptId":"risk-it-general-controls-017","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The client relies on an automated three-way match control, but programmers can move changes to production without approval. What should the auditor do before relying on the automated control?","choices":["Evaluate relevant IT general controls over program changes and access.","Rely on the automated control because automation cannot be overridden.","Ignore IT controls and reduce substantive testing.","Test only the paper invoices."],"ans":"A","exp":"ITGCs support the reliability of automated controls and reports."},{"id":"risk-008","sec":"risk","topic":"Control environment","conceptId":"risk-control-environment-008","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The owner pressures staff to record shipments before goods leave the warehouse. Which risk factor is most relevant?","choices":["A restriction on auditor independence only.","A sampling risk only.","A weak control environment and management override risk.","A routine timing difference with no fraud implication."],"ans":"C","exp":"Tone at the top and management override affect overall audit risk."},{"id":"risk-018","sec":"risk","topic":"Control environment","conceptId":"risk-control-environment-018","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management emphasizes meeting aggressive earnings targets and dismisses control exceptions as “not worth documenting.” What does this suggest?","choices":["Potential control environment weakness affecting risk assessment.","A reason to eliminate fraud brainstorming.","Evidence that controls are operating effectively.","An automatic requirement to withdraw from the audit."],"ans":"A","exp":"Tone at the top and management override affect overall audit risk."},{"id":"risk-009","sec":"risk","topic":"Significant risks","conceptId":"risk-significant-risks-009","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A large unusual related-party sale occurs two days before year-end with extended payment terms. How should it usually be treated?","choices":["As evidence that controls are effective.","As automatically immaterial because payment is extended.","As a significant risk requiring special audit consideration.","As low risk because related parties are familiar with the client."],"ans":"C","exp":"Unusual related-party transactions often require special audit consideration."},{"id":"risk-019","sec":"risk","topic":"Significant risks","conceptId":"risk-significant-risks-019","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A complex revenue arrangement requires significant judgment about performance obligations. How should it be treated in planning?","choices":["Consider whether it is a significant risk requiring specific audit attention.","Exclude it from planning because judgmental areas are management’s responsibility.","Test it only through bank confirmations.","Assume it is immaterial if revenue was collected in cash."],"ans":"A","exp":"Unusual related-party transactions often require special audit consideration."},{"id":"risk-010","sec":"risk","topic":"Related-party risks","conceptId":"risk-related-party-risks-010","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor suspects an undisclosed entity controlled by the CEO leased equipment to the company. Which procedure is most appropriate?","choices":["Assume disclosure is unnecessary if paid in cash.","Exclude the transaction from the audit because it is not with a customer.","Ask management once and perform no further work.","Inspect minutes, conflict disclosures, confirmations, and other records for related-party relationships and terms."],"ans":"D","exp":"Related-party procedures focus on identification, business purpose, authorization, and disclosure."},{"id":"risk-020","sec":"risk","topic":"Related-party risks","conceptId":"risk-related-party-risks-020","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A company leases equipment from an entity owned by the CEO’s sibling, but the arrangement is not in the related-party listing. What should the auditor do?","choices":["Perform procedures to identify, evaluate, and disclose related-party relationships and transactions.","Ignore the transaction because a sibling is not management.","Accept the related-party listing as complete without inquiry.","Automatically issue a disclaimer."],"ans":"A","exp":"Related-party procedures focus on identification, business purpose, authorization, and disclosure."},{"id":"evidence-001","sec":"evidence","topic":"Audit evidence","conceptId":"evidence-audit-evidence-001","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The client provides an internally prepared aging report for receivables. What should the auditor consider before relying on it?","choices":["Assume it is reliable because it came from the accounting system.","Test the report for completeness and accuracy and obtain corroborating evidence.","Use it as sufficient evidence without further work.","Reject it automatically even if controls are strong."],"ans":"B","exp":"Evidence from internal reports may require testing of underlying data."},{"id":"evidence-011","sec":"evidence","topic":"Audit evidence","conceptId":"evidence-audit-evidence-011","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The auditor has an internally prepared schedule, management explanation, and a third-party confirmation. Which evidence is generally most persuasive?","choices":["The third-party confirmation obtained directly by the auditor.","The management explanation alone.","The client-prepared schedule without testing.","A verbal statement from the bookkeeper."],"ans":"A","exp":"Evidence from internal reports may require testing of underlying data."},{"id":"evidence-002","sec":"evidence","topic":"Confirmations","conceptId":"evidence-confirmations-002","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A customer does not respond to a positive confirmation request. What should the auditor do next?","choices":["Delete the customer from the sample.","Treat the balance as confirmed because no disagreement was received.","Ask management to sign the confirmation for the customer.","Perform alternative procedures such as examining subsequent cash receipts and shipping documents."],"ans":"D","exp":"Positive confirmations require a response; nonresponses need follow-up or alternative procedures."},{"id":"evidence-012","sec":"evidence","topic":"Confirmations","conceptId":"evidence-confirmations-012","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A major customer does not respond to a positive confirmation request. What should the auditor do?","choices":["Perform alternative procedures such as examining subsequent cash receipts and shipping documents.","Treat the balance as confirmed because no disagreement was received.","Delete the customer from the sample.","Ask management to sign the confirmation instead."],"ans":"A","exp":"Positive confirmations require a response; nonresponses need follow-up or alternative procedures."},{"id":"evidence-003","sec":"evidence","topic":"Inventory observation","conceptId":"evidence-inventory-observation-003","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"During the physical count, the auditor traces items from the warehouse floor to count sheets and from count sheets to the floor. What assertions are addressed?","choices":["Only presentation and disclosure.","Only valuation of inventory.","Only rights and obligations.","Completeness and existence of inventory quantities."],"ans":"D","exp":"Floor-to-sheet supports completeness; sheet-to-floor supports existence."},{"id":"evidence-013","sec":"evidence","topic":"Inventory observation","conceptId":"evidence-inventory-observation-013","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"During inventory observation, the auditor identifies unnumbered count tags and shipping during the count. What is the main audit concern?","choices":["Existence and completeness of inventory counts and cutoff.","Only depreciation expense.","Whether legal letters were mailed.","The wording of the audit report title."],"ans":"A","exp":"Floor-to-sheet supports completeness; sheet-to-floor supports existence."},{"id":"evidence-004","sec":"evidence","topic":"Sampling","conceptId":"evidence-sampling-004","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor lowers tolerable misstatement for accounts receivable. What is the likely effect on sample size?","choices":["Sample size is unaffected in all cases.","Sampling risk is eliminated.","Sample size generally decreases.","Sample size generally increases."],"ans":"D","exp":"Lower tolerable misstatement generally requires more testing."},{"id":"evidence-014","sec":"evidence","topic":"Sampling","conceptId":"evidence-sampling-014","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A sample has more deviations than the tolerable deviation rate. What is the appropriate conclusion?","choices":["The auditor should consider the control ineffective or expand/modify testing as appropriate.","The auditor should ignore deviations if the sample was random.","Sampling results never affect audit strategy.","The auditor should change the answer key."],"ans":"A","exp":"Lower tolerable misstatement generally requires more testing."},{"id":"evidence-005","sec":"evidence","topic":"Substantive analytics","conceptId":"evidence-substantive-analytics-005","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor estimates payroll expense using headcount, approved pay rates, and known bonus changes. What is necessary for substantive analytics to be effective?","choices":["No need to test data used in the expectation.","A precise, reliable expectation and investigation of significant differences.","A vague expectation that payroll should increase.","Use only management’s final balance as the expectation."],"ans":"B","exp":"Substantive analytics require reliable data and sufficient precision."},{"id":"evidence-015","sec":"evidence","topic":"Substantive analytics","conceptId":"evidence-substantive-analytics-015","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Substantive analytics identify a plausible expectation for payroll expense, but the recorded amount differs materially. What should the auditor do?","choices":["Investigate the difference and obtain corroborating evidence.","Accept the recorded amount because analytics are only optional.","Use the difference as evidence that payroll is correct.","Avoid documenting the expectation."],"ans":"A","exp":"Substantive analytics require reliable data and sufficient precision."},{"id":"evidence-006","sec":"evidence","topic":"Accounts receivable","conceptId":"evidence-accounts-receivable-006","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Which procedure best supports existence of a material accounts receivable balance?","choices":["Inspect the client’s chart of accounts.","Send confirmations directly to customers and control the mailing and responses.","Compare current-year depreciation expense to prior year.","Read the board minutes only."],"ans":"B","exp":"External confirmations provide evidence from independent third parties."},{"id":"evidence-016","sec":"evidence","topic":"Accounts receivable","conceptId":"evidence-accounts-receivable-016","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"An A/R aging shows a large overdue balance from a customer with no subsequent receipts. Which assertion is most directly affected?","choices":["Valuation/collectibility of receivables.","Presentation of depreciation.","Completeness of accounts payable.","Occurrence of payroll expense."],"ans":"A","exp":"External confirmations provide evidence from independent third parties."},{"id":"evidence-007","sec":"evidence","topic":"Estimates","conceptId":"evidence-estimates-007","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Management’s allowance for doubtful accounts is much lower than historical collection experience suggests. What should the auditor do?","choices":["Evaluate the method, assumptions, data, and possible management bias.","Ignore subsequent collections because they occurred after year-end.","Replace management’s estimate without audit documentation.","Accept the estimate because estimates are management’s responsibility."],"ans":"A","exp":"Auditing estimates includes testing methods, assumptions, data, and bias."},{"id":"evidence-017","sec":"evidence","topic":"Estimates","conceptId":"evidence-estimates-017","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management’s warranty estimate uses historical claims but excludes a known product defect discovered before report release. What should the auditor do?","choices":["Evaluate whether the estimate includes relevant current information and challenge unsupported assumptions.","Accept the estimate because estimates cannot be audited.","Use only last year’s percentage without inquiry.","Ignore the defect if management signs a representation letter."],"ans":"A","exp":"Auditing estimates includes testing methods, assumptions, data, and bias."},{"id":"evidence-008","sec":"evidence","topic":"Fair value","conceptId":"evidence-fair-value-008","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The client values a complex investment using unobservable inputs. What is a likely audit response?","choices":["Accept the valuation because Level 3 inputs cannot be audited.","Avoid specialist work because auditors may never use specialists.","Use cost as the audit value in all cases.","Test significant assumptions, evaluate specialists if used, and consider disclosure adequacy."],"ans":"D","exp":"Level 3 fair values require heightened testing and skepticism."},{"id":"evidence-018","sec":"evidence","topic":"Fair value","conceptId":"evidence-fair-value-018","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A fair value estimate is based on an unobservable input supplied by management. Which audit response is appropriate?","choices":["Test the reasonableness of significant assumptions and consider specialist evidence if needed.","Accept the estimate because fair values are subjective.","Remove the estimate from the financial statements.","Rely only on board approval."],"ans":"A","exp":"Level 3 fair values require heightened testing and skepticism."},{"id":"evidence-009","sec":"evidence","topic":"Subsequent receipts","conceptId":"evidence-subsequent-receipts-009","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"January cash collections are examined for December receivables. What evidence can this provide?","choices":["Evidence that inventory cutoff is correct.","Support for existence and valuation/collectibility of year-end receivables.","Evidence that all liabilities are complete.","Proof that all December sales were recorded."],"ans":"B","exp":"Subsequent receipts can corroborate receivable balances."},{"id":"evidence-019","sec":"evidence","topic":"Subsequent receipts","conceptId":"evidence-subsequent-receipts-019","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"For an overdue receivable, the client provides a cash receipt dated January 18. What does this evidence primarily support?","choices":["Existence and valuation of the receivable at year-end, subject to cutoff evaluation.","Completeness of inventory.","The effectiveness of payroll controls.","A going-concern conclusion in all cases."],"ans":"A","exp":"Subsequent receipts can corroborate receivable balances."},{"id":"evidence-010","sec":"evidence","topic":"Cutoff","conceptId":"evidence-cutoff-010","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor compares shipping documents immediately before and after year-end to recorded sales invoices. What is the objective?","choices":["Determine whether payroll taxes were accrued.","Verify the legal ownership of common stock.","Determine whether sales were recorded in the proper period.","Evaluate board independence."],"ans":"C","exp":"Cutoff testing focuses on recording transactions in the correct period."},{"id":"evidence-020","sec":"evidence","topic":"Cutoff","conceptId":"evidence-cutoff-020","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Goods shipped on December 31 were invoiced on January 3. Which procedure is most relevant?","choices":["Test shipping documents, invoices, and sales entries around year-end cutoff.","Confirm bank balances only.","Review attorney letters only.","Recalculate depreciation expense."],"ans":"A","exp":"Cutoff testing focuses on recording transactions in the correct period."},{"id":"reporting-001","sec":"reporting","topic":"Audit opinion","conceptId":"reporting-audit-opinion-001","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A material GAAP departure is not pervasive. What opinion is generally appropriate?","choices":["Unmodified opinion with no paragraph.","Qualified opinion.","Disclaimer of opinion.","Adverse opinion in all cases."],"ans":"B","exp":"Material but not pervasive misstatements generally result in a qualified opinion."},{"id":"reporting-011","sec":"reporting","topic":"Audit opinion","conceptId":"reporting-audit-opinion-011","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management refuses to correct a material inventory overstatement that is not pervasive. What report effect is most likely?","choices":["A qualified opinion for a material GAAP departure.","An unmodified opinion because management refused the entry.","A disclaimer because all GAAP departures are scope limitations.","An adverse opinion in all nonpervasive cases."],"ans":"A","exp":"Material but not pervasive misstatements generally result in a qualified opinion."},{"id":"reporting-002","sec":"reporting","topic":"Emphasis-of-matter","conceptId":"reporting-emphasis-of-matter-002","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A significant uncertainty is properly disclosed and the auditor wants to draw attention to it without modifying the opinion. Which paragraph may be used?","choices":["Management responsibility paragraph only.","Scope limitation paragraph.","Emphasis-of-matter paragraph.","Adverse opinion paragraph."],"ans":"C","exp":"An EOM paragraph highlights appropriately presented or disclosed matters."},{"id":"reporting-012","sec":"reporting","topic":"Emphasis-of-matter","conceptId":"reporting-emphasis-of-matter-012","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The financial statements are fairly stated, but there is a properly disclosed unusually important subsequent event. What paragraph may be appropriate?","choices":["An emphasis-of-matter paragraph referring to the disclosure.","A qualified opinion solely because the matter is important.","A disclaimer of opinion.","No audit report can be issued."],"ans":"A","exp":"An EOM paragraph highlights appropriately presented or disclosed matters."},{"id":"reporting-003","sec":"reporting","topic":"Other-matter paragraph","conceptId":"reporting-other-matter-paragraph-003","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor wants to restrict use of a report prepared for a regulatory agency. Which paragraph is most likely relevant?","choices":["Emphasis-of-matter paragraph for a financial statement matter only.","No paragraph is ever allowed for restriction of use.","Other-matter paragraph.","Disclaimer paragraph because all restricted reports disclaim."],"ans":"C","exp":"Other-matter paragraphs address matters outside the financial statements relevant to users."},{"id":"reporting-013","sec":"reporting","topic":"Other-matter paragraph","conceptId":"reporting-other-matter-paragraph-013","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The auditor is asked to refer to required supplementary information in the auditor’s report. Which paragraph is commonly used for matters other than those presented or disclosed in the financial statements?","choices":["Other-matter paragraph.","Adverse opinion paragraph.","Management responsibility paragraph only.","Scope limitation paragraph in all cases."],"ans":"A","exp":"Other-matter paragraphs address matters outside the financial statements relevant to users."},{"id":"reporting-004","sec":"reporting","topic":"Going concern","conceptId":"reporting-going-concern-004","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Substantial doubt exists and disclosures are adequate. What is the typical reporting effect?","choices":["Always disclaim an opinion.","Always issue an adverse opinion.","Include an emphasis-of-matter paragraph and do not modify the opinion solely for going concern.","Omit any reference because disclosure is adequate."],"ans":"C","exp":"Adequately disclosed going-concern uncertainty may require an EOM paragraph."},{"id":"reporting-014","sec":"reporting","topic":"Going concern","conceptId":"reporting-going-concern-014","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Substantial doubt about going concern exists and management’s disclosure is adequate. What report modification is generally appropriate?","choices":["Unmodified opinion with a going-concern emphasis section/paragraph as required.","Adverse opinion because going concern always means GAAP departure.","Disclaimer of opinion in all cases.","No reference to going concern is permitted."],"ans":"A","exp":"Adequately disclosed going-concern uncertainty may require an EOM paragraph."},{"id":"reporting-005","sec":"reporting","topic":"Subsequent events","conceptId":"reporting-subsequent-events-005","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"A customer files bankruptcy after year-end due to financial problems that existed at year-end. How should this be treated?","choices":["As a reason to withdraw automatically.","As an event that never affects the audit.","As a recognized subsequent event affecting year-end collectibility.","As a nonrecognized event unrelated to year-end."],"ans":"C","exp":"Subsequent events that provide evidence about year-end conditions may require adjustment."},{"id":"reporting-015","sec":"reporting","topic":"Subsequent events","conceptId":"reporting-subsequent-events-015","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"A customer bankruptcy after year-end provides evidence of financial difficulty existing at year-end. What is the likely accounting/audit treatment?","choices":["Evaluate adjustment of the receivable allowance and related disclosure.","Treat it only as a next-year event with no current-year effect.","Ignore it because it occurred after year-end.","Automatically withdraw from the engagement."],"ans":"A","exp":"Subsequent events that provide evidence about year-end conditions may require adjustment."},{"id":"reporting-006","sec":"reporting","topic":"Written representations","conceptId":"reporting-written-representations-006","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Management refuses to provide written representations. What is the likely effect?","choices":["Adverse opinion for GAAP departure in all cases.","No effect because oral representations are enough.","Automatic unmodified opinion.","A scope limitation that may result in a disclaimer or withdrawal."],"ans":"D","exp":"Written representations are required and complement other evidence."},{"id":"reporting-016","sec":"reporting","topic":"Written representations","conceptId":"reporting-written-representations-016","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management refuses to provide written representations. What is the likely effect?","choices":["A scope limitation that may result in disclaimer or withdrawal.","No effect because oral representations are enough.","Automatic unmodified opinion.","Adverse opinion for GAAP departure in all cases."],"ans":"A","exp":"Written representations are required and complement other evidence."},{"id":"reporting-007","sec":"reporting","topic":"Comparative statements","conceptId":"reporting-comparative-statements-007","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"Current-year statements include prior-year statements audited by a predecessor whose report is not reissued. What may the successor auditor do?","choices":["Remove the prior-year statements from the report without disclosure.","Ignore the predecessor opinion.","Refer to the predecessor auditor’s report in an other-matter paragraph when appropriate.","Assume responsibility for the predecessor’s audit without procedures."],"ans":"C","exp":"Comparative reporting requires appropriate reference to predecessor involvement when applicable."},{"id":"reporting-017","sec":"reporting","topic":"Comparative statements","conceptId":"reporting-comparative-statements-017","difficulty":"Medium","questionType":"Remembering/Understanding","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Current-year statements are audited by the successor auditor and prior-year statements were audited by a predecessor auditor. What reporting issue should be addressed?","choices":["Whether to refer to the predecessor auditor’s report or reissue arrangements as appropriate.","Always combine both years into one opinion without reference.","Ignore the prior year because it is comparative.","Automatically disclaim the current year."],"ans":"A","exp":"Comparative reporting requires appropriate reference to predecessor involvement when applicable."},{"id":"reporting-008","sec":"reporting","topic":"Other information","conceptId":"reporting-other-information-008","difficulty":"Easy","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The annual report contains unaudited operating statistics inconsistent with the audited financial statements. What should the auditor do?","choices":["Discuss with management and request correction of material inconsistencies or misstatements of fact.","Issue an adverse opinion solely because other information exists.","Audit the other information as a separate engagement automatically.","Ignore it because it is outside the financial statements."],"ans":"A","exp":"Auditors read other information for material inconsistencies."},{"id":"reporting-018","sec":"reporting","topic":"Other information","conceptId":"reporting-other-information-018","difficulty":"Medium","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"The annual report contains other information inconsistent with the audited financial statements. What should the auditor do?","choices":["Discuss the inconsistency with management and determine whether revision or further action is needed.","Ignore other information because it is never read by auditors.","Issue an adverse opinion automatically.","Change the audit opinion without investigating."],"ans":"A","exp":"Auditors read other information for material inconsistencies."},{"id":"reporting-009","sec":"reporting","topic":"Scope limitation","conceptId":"reporting-scope-limitation-009","difficulty":"Medium","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The auditor cannot observe inventory and cannot perform alternative procedures for a material balance. What opinion issue is present?","choices":["No reporting effect because inventory is physical.","A scope limitation that may require a qualified opinion or disclaimer depending on pervasiveness.","An emphasis paragraph with unmodified opinion in all cases.","A GAAP departure requiring adverse opinion."],"ans":"B","exp":"Inability to obtain sufficient appropriate evidence is a scope limitation."},{"id":"reporting-019","sec":"reporting","topic":"Scope limitation","conceptId":"reporting-scope-limitation-019","difficulty":"Hard","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Management prevents observation of inventory and alternative procedures cannot provide sufficient appropriate evidence. What report effect may result?","choices":["A qualified opinion or disclaimer depending on materiality/pervasiveness of the scope limitation.","An unmodified opinion because inventory is management’s responsibility.","An adverse opinion because scope limitations are GAAP departures.","No report can ever be issued."],"ans":"A","exp":"Inability to obtain sufficient appropriate evidence is a scope limitation."},{"id":"reporting-010","sec":"reporting","topic":"GAAP departure","conceptId":"reporting-gaap-departure-010","difficulty":"Hard","questionType":"Professional Judgment","sourceType":"Original CPA-style","source":"Original CPA-style question","releaseYear":null,"q":"The client refuses to consolidate a material subsidiary and the effect is pervasive. What opinion is appropriate?","choices":["Qualified opinion only, regardless of pervasiveness.","Unmodified opinion with emphasis paragraph only.","Adverse opinion.","Disclaimer because the auditor lacks independence."],"ans":"C","exp":"Material and pervasive GAAP departures result in an adverse opinion."},{"id":"reporting-020","sec":"reporting","topic":"GAAP departure","conceptId":"reporting-gaap-departure-020","difficulty":"Easy","questionType":"Analysis","sourceType":"Original CPA-style","source":"Original CPA-style question - revised v8.1.7","releaseYear":null,"q":"Financial statements omit required segment disclosures and the omission is material and pervasive. What opinion is most appropriate?","choices":["Adverse opinion for a pervasive GAAP departure.","Disclaimer because disclosure omissions are always scope limitations.","Unmodified opinion with no mention.","Qualified opinion in all pervasive cases."],"ans":"A","exp":"Material and pervasive GAAP departures result in an adverse opinion."},{"id":"ethics-8x-01","sec":"ethics","topic":"Financial Interests","conceptId":"ethics-8x-01","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A staff auditor assigned to inventory testing learns she owns shares of the audit client through a personal brokerage account. What should happen before she performs audit work?","choices":["Proceed because inventory is unrelated to the investment account.","Dispose of the direct financial interest or remove the staff member from the engagement.","Have management acknowledge the investment in the representation letter.","Disclose the investment in the audit report."],"ans":"B","exp":"A direct financial interest in an attest client impairs independence for a covered member regardless of materiality."},{"id":"ethics-8x-02","sec":"ethics","topic":"Management Responsibilities","conceptId":"ethics-8x-02","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"An audit client asks the auditor to select the depreciation method for a new class of assets. What is the appropriate response?","choices":["Select the method if the client later signs the financial statements.","Select the method if the assets are immaterial.","Decline to make the decision because selecting accounting policy is a management responsibility.","Perform the service and add an emphasis-of-matter paragraph."],"ans":"C","exp":"Auditors may assist with calculations, but management must make accounting-policy decisions and accept responsibility."},{"id":"ethics-8x-03","sec":"ethics","topic":"Predecessor Auditor","conceptId":"ethics-8x-03","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A prospective client refuses to allow communication with the predecessor auditor. What is the best response?","choices":["Accept and perform more substantive procedures.","Treat the refusal as a significant acceptance risk and normally decline or delay acceptance.","Accept if fees are paid in advance.","Ask the predecessor auditor for workpapers without client permission."],"ans":"B","exp":"Refusal to permit predecessor communication raises concerns about management integrity and engagement acceptance."},{"id":"ethics-8x-04","sec":"ethics","topic":"Confidentiality","conceptId":"ethics-8x-04","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A CPA receives a subpoena for client records. Which action is most appropriate?","choices":["Ignore it because confidentiality always prohibits disclosure.","Immediately post the records to the firm portal.","Consult legal counsel and respond as required by law or regulation.","Call the client and ask whether audit evidence may be destroyed."],"ans":"C","exp":"Confidentiality has exceptions for legal requirements, peer review, quality review, and authorized professional obligations."},{"id":"ethics-8x-05","sec":"ethics","topic":"Documentation","conceptId":"ethics-8x-05","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"An audit manager reviews workpapers after report release and wants to delete a memo that contradicts the final conclusion. What is appropriate?","choices":["Delete it because the final conclusion is documented elsewhere.","Retain the original documentation and add clarifying documentation with the reason and date of the change.","Backdate a replacement memo.","Remove the memo if no misstatement was found."],"ans":"B","exp":"After documentation completion, changes should show what changed, when, by whom, and why; contradictory evidence should not be erased."},{"id":"ethics-8x-06","sec":"ethics","topic":"Due Care","conceptId":"ethics-8x-06","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A firm accepts an audit in a specialized industry without sufficient expertise. What should the firm do?","choices":["Rely entirely on management representations.","Use specialists or obtain competence before performing the engagement.","Issue a disclaimer automatically.","Perform only analytical procedures."],"ans":"B","exp":"Due professional care requires adequate competence, supervision, and appropriate involvement of specialists when needed."},{"id":"ethics-8x-07","sec":"ethics","topic":"Quality Management","conceptId":"ethics-8x-07","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A firm identifies recurring inspection findings in revenue testing. What is the most appropriate quality response?","choices":["Ignore because findings relate to prior engagements.","Perform root-cause analysis and update policies, training, or monitoring.","Ask clients to waive revenue testing.","Remove all revenue procedures from audit programs."],"ans":"B","exp":"Quality management requires monitoring and remediation of identified deficiencies."},{"id":"ethics-8x-08","sec":"ethics","topic":"Threats Safeguards","conceptId":"ethics-8x-08","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A client offers the engagement partner a costly vacation package during the audit. What should the auditor do?","choices":["Accept if disclosed to the audit committee.","Accept if the client says it is normal business hospitality.","Decline the gift and evaluate any independence threat.","Accept and reduce the audit fee."],"ans":"C","exp":"Gifts or favors may create familiarity, undue influence, or self-interest threats that client consent does not cure."},{"id":"ethics-8x-09","sec":"ethics","topic":"Management Integrity","conceptId":"ethics-8x-09","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"During acceptance, the auditor learns management frequently pressures prior auditors to waive adjustments. What is the best next step?","choices":["Accept because all clients negotiate adjustments.","Evaluate management integrity and consider declining the engagement.","Plan fewer procedures to avoid conflict.","Issue an adverse opinion before fieldwork."],"ans":"B","exp":"Management integrity is a core acceptance consideration because it affects representations and audit evidence reliability."},{"id":"ethics-8x-10","sec":"ethics","topic":"Engagement Letter","conceptId":"ethics-8x-10","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which item should ordinarily be included in an audit engagement letter?","choices":["A guarantee that all fraud will be detected.","Management responsibility for the financial statements and internal control.","A promise to issue an unmodified opinion.","The exact amount of every adjusting entry."],"ans":"B","exp":"The engagement letter documents responsibilities, scope, framework, and limitations; it does not guarantee outcomes."},{"id":"ethics-8x-11","sec":"ethics","topic":"Professional Skepticism","conceptId":"ethics-8x-11","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Management provides unusually vague explanations for a large year-end estimate. What should the auditor do?","choices":["Accept because management is responsible for estimates.","Reduce sample sizes to avoid bias.","Seek corroborating evidence and evaluate contradictory information.","Rely only on prior-year workpapers."],"ans":"C","exp":"Professional skepticism includes a questioning mind and critical assessment of audit evidence."},{"id":"ethics-8x-12","sec":"ethics","topic":"Independence Appearance","conceptId":"ethics-8x-12","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A retired audit partner joins the client as CFO before safeguards are evaluated. What should the firm evaluate?","choices":["Only whether the partner still owns firm shares.","Whether independence is impaired in fact or appearance and whether required safeguards are in place.","Whether the client agrees to disclose the hire.","Whether the new CFO signs the management representation letter."],"ans":"B","exp":"Former partner employment relationships can create independence threats requiring safeguards and evaluation."},{"id":"risk-8x-01","sec":"risk","topic":"Revenue Risk","conceptId":"risk-8x-01","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"December revenue doubled while shipments declined and manual shipping overrides increased. What risk should be emphasized?","choices":["Completeness of payroll.","Cutoff and occurrence of revenue.","Valuation of prepaid insurance.","Presentation of debt covenants only."],"ans":"B","exp":"A spike in revenue with shipping anomalies suggests cutoff/occurrence risk and possible fraud risk."},{"id":"risk-8x-02","sec":"risk","topic":"Walkthroughs","conceptId":"risk-8x-02","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"What is the main purpose of performing a walkthrough of a significant transaction cycle?","choices":["To replace substantive testing.","To confirm understanding of process flow, controls, and points where misstatements could occur.","To guarantee the control operated all year.","To avoid identifying fraud risks."],"ans":"B","exp":"Walkthroughs help the auditor understand design and implementation; they do not prove operating effectiveness for the full period."},{"id":"risk-8x-03","sec":"risk","topic":"Materiality","conceptId":"risk-8x-03","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"When planning materiality is lowered after interim testing, what should the auditor consider?","choices":["Ignore the change because planning is complete.","Whether additional procedures are needed for work already performed.","Increase tolerable misstatement automatically.","Issue a qualified opinion."],"ans":"B","exp":"A lower materiality threshold may require reconsideration of nature, timing, and extent of procedures."},{"id":"risk-8x-04","sec":"risk","topic":"Fraud Risk","conceptId":"risk-8x-04","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which condition most directly indicates opportunity for fraudulent financial reporting?","choices":["Strong segregation of duties.","Audit committee meets without management.","CFO can post manual journal entries without independent review.","Employees take mandatory vacations."],"ans":"C","exp":"Unreviewed manual entries by senior finance personnel create opportunity for management override."},{"id":"risk-8x-05","sec":"risk","topic":"Controls Reliance","conceptId":"risk-8x-05","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"The auditor plans to rely on an automated three-way-match control. What must be evaluated?","choices":["Only the year-end output.","Relevant IT general controls and operation of the automated control.","Only the controller representation.","Whether the prior-year audit was unmodified."],"ans":"B","exp":"Reliance on automated controls depends on application control effectiveness and relevant ITGCs."},{"id":"risk-8x-06","sec":"risk","topic":"Analytics","conceptId":"risk-8x-06","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A preliminary analytical procedure shows gross margin increased sharply with no business explanation. What should the auditor do?","choices":["Ignore because analytics are optional.","Identify and assess risks and design procedures responsive to the fluctuation.","Conclude revenue is fairly stated.","Reduce testing because margins improved."],"ans":"B","exp":"Unexpected analytical relationships may indicate risk and require follow-up."},{"id":"risk-8x-07","sec":"risk","topic":"Control Environment","conceptId":"risk-8x-07","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Management routinely bypasses approval controls for large purchases. What is the likely effect?","choices":["Lower risk of material misstatement.","A stronger control environment.","Increased control risk and possible need for more substantive procedures.","No audit effect if purchases are recorded."],"ans":"C","exp":"Management override or bypass weakens the control environment and increases risk."},{"id":"risk-8x-08","sec":"risk","topic":"Related Parties","conceptId":"risk-8x-08","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which procedure helps identify related-party relationships during planning?","choices":["Avoid inquiries to reduce bias.","Read minutes, inquire of management, and inspect conflict-of-interest information.","Rely only on bank confirmations.","Confirm all vendors with customers."],"ans":"B","exp":"Related-party risk assessment includes inquiries and inspection of governance and business records."},{"id":"risk-8x-09","sec":"risk","topic":"Going Concern Risk","conceptId":"risk-8x-09","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A client violates debt covenants and loses its primary lender after year-end. What should the auditor evaluate?","choices":["Only tax presentation.","Management plans and substantial doubt about going concern.","Whether inventory count was observed.","Whether confirmations were mailed."],"ans":"B","exp":"Liquidity events and covenant violations may create substantial doubt requiring evaluation and disclosure consideration."},{"id":"risk-8x-10","sec":"risk","topic":"Significant Risks","conceptId":"risk-8x-10","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A complex fair value estimate uses unobservable inputs and management bonuses depend on earnings. How should it be treated?","choices":["As a low-risk routine estimate.","As a likely significant risk requiring focused procedures.","As a scope limitation automatically.","As irrelevant because estimates are subjective."],"ans":"B","exp":"Complex estimates with incentives and subjectivity often create significant risks."},{"id":"risk-8x-11","sec":"risk","topic":"Audit Strategy","conceptId":"risk-8x-11","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"What does the overall audit strategy establish?","choices":["Detailed results of every test.","Scope, timing, direction, and resource considerations for the audit.","Only the final opinion wording.","Only the client representation letter."],"ans":"B","exp":"The strategy sets audit direction; the audit plan contains detailed procedures."},{"id":"risk-8x-12","sec":"risk","topic":"Inherent Risk","conceptId":"risk-8x-12","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A new revenue system goes live two weeks before year-end. What risk increases?","choices":["Only disclosure risk for leases.","Risk of processing errors and incomplete/incorrect revenue data.","Risk that cash is overstated only.","No risk because new systems are always better."],"ans":"B","exp":"System conversions near year-end increase inherent and control risk around affected transactions."},{"id":"evidence-8x-01","sec":"evidence","topic":"External Confirmations","conceptId":"evidence-8x-01","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A positive confirmation is returned directly by the customer disputing the balance. What should the auditor do?","choices":["Treat nonagreement as proof the client is wrong.","Investigate the exception and obtain supporting evidence.","Ignore because confirmations are unreliable.","Ask management to sign the confirmation."],"ans":"B","exp":"Confirmation exceptions require follow-up to determine whether they represent misstatements."},{"id":"evidence-8x-02","sec":"evidence","topic":"Inventory Observation","conceptId":"evidence-8x-02","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"The auditor cannot attend the year-end inventory count. What is the best response?","choices":["Automatically disclaim the opinion.","Perform alternative procedures such as observing a later count and testing roll-forward, if practicable.","Accept management representation only.","Omit inventory from the audit."],"ans":"B","exp":"Alternative procedures may provide evidence if observation at year-end was not possible."},{"id":"evidence-8x-03","sec":"evidence","topic":"Sampling","conceptId":"evidence-8x-03","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"What happens when tolerable misstatement decreases, all else equal?","choices":["Required sample size generally increases.","Required sample size generally decreases.","Sampling risk is eliminated.","No effect occurs."],"ans":"A","exp":"Lower tolerable misstatement requires more persuasive evidence and usually a larger sample."},{"id":"evidence-8x-04","sec":"evidence","topic":"Estimates","conceptId":"evidence-8x-04","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"For a significant accounting estimate, which evidence is most persuasive?","choices":["Management opinion without support.","Testing management’s process, developing an independent expectation, or reviewing subsequent events.","A prior-year memo copied forward.","The engagement letter."],"ans":"B","exp":"Estimates require evidence about methods, data, assumptions, and subsequent outcomes where relevant."},{"id":"evidence-8x-05","sec":"evidence","topic":"Subsequent Receipts","conceptId":"evidence-8x-05","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which procedure is commonly used to test existence/valuation of accounts receivable?","choices":["Trace subsequent cash receipts to outstanding customer balances.","Inspect fixed asset title documents only.","Count petty cash.","Read board minutes only."],"ans":"A","exp":"Subsequent cash collections provide evidence about receivable existence and collectibility."},{"id":"evidence-8x-06","sec":"evidence","topic":"Legal Letters","conceptId":"evidence-8x-06","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Why does the auditor send an inquiry letter to external legal counsel?","choices":["To ask counsel to prepare the financial statements.","To obtain evidence about litigation, claims, and assessments.","To confirm all bank accounts.","To determine payroll cutoff."],"ans":"B","exp":"Attorney letters provide evidence about contingencies and litigation disclosures."},{"id":"evidence-8x-07","sec":"evidence","topic":"Management Representations","conceptId":"evidence-8x-07","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which statement about written representations is correct?","choices":["They replace other audit evidence.","They complement other evidence but do not substitute for necessary procedures.","They are unnecessary if the opinion is unmodified.","They eliminate the need to evaluate fraud risk."],"ans":"B","exp":"Written representations are required but cannot replace sufficient appropriate evidence."},{"id":"evidence-8x-08","sec":"evidence","topic":"Reperformance","conceptId":"evidence-8x-08","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Recalculating depreciation expense is an example of what type of procedure?","choices":["Inquiry only.","Reperformance/recalculation.","Observation of controls.","External confirmation."],"ans":"B","exp":"Recalculation checks mathematical accuracy of amounts or schedules."},{"id":"evidence-8x-09","sec":"evidence","topic":"Audit Evidence Reliability","conceptId":"evidence-8x-09","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which evidence is generally most reliable?","choices":["Evidence obtained directly by the auditor from an independent external source.","A verbal statement from the bookkeeper.","An internally prepared spreadsheet with no review.","A draft memo from management."],"ans":"A","exp":"External evidence obtained directly by the auditor is generally more reliable than internal oral evidence."},{"id":"evidence-8x-10","sec":"evidence","topic":"Cutoff Testing","conceptId":"evidence-8x-10","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"To test sales cutoff, which population is most relevant?","choices":["Shipments and invoices around year-end.","Checks written six months after year-end.","All depreciation schedules.","Only board compensation minutes."],"ans":"A","exp":"Cutoff tests focus on transactions near period end."},{"id":"evidence-8x-11","sec":"evidence","topic":"Specialists","conceptId":"evidence-8x-11","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"When using an auditor’s specialist, what should the auditor evaluate?","choices":["Only the specialist’s fee.","Competence, capabilities, objectivity, and the adequacy of the work.","Whether management likes the specialist.","Whether the specialist signs the audit report."],"ans":"B","exp":"The auditor remains responsible for evaluating the specialist and the evidence obtained."},{"id":"evidence-8x-12","sec":"evidence","topic":"Journal Entries","conceptId":"evidence-8x-12","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which procedure responds to management override risk?","choices":["Test selected journal entries and adjustments, especially unusual or late entries.","Avoid inquiry of accounting personnel.","Rely only on the prior-year audit.","Perform no procedures if controls appear strong."],"ans":"A","exp":"Testing journal entries is a required response to management override risk."},{"id":"reporting-8x-01","sec":"reporting","topic":"Qualified Opinion","conceptId":"reporting-8x-01","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A material but not pervasive GAAP departure remains uncorrected. What opinion is appropriate?","choices":["Unmodified opinion.","Qualified opinion.","Disclaimer of opinion.","Adverse opinion automatically."],"ans":"B","exp":"A material but not pervasive misstatement generally results in a qualified opinion."},{"id":"reporting-8x-02","sec":"reporting","topic":"Adverse Opinion","conceptId":"reporting-8x-02","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Financial statements are materially and pervasively misstated. What opinion is appropriate?","choices":["Adverse opinion.","Disclaimer of opinion.","Unmodified opinion with emphasis-of-matter.","Qualified opinion only."],"ans":"A","exp":"Pervasive material misstatements result in an adverse opinion."},{"id":"reporting-8x-03","sec":"reporting","topic":"Disclaimer","conceptId":"reporting-8x-03","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A severe scope limitation prevents obtaining sufficient appropriate evidence and possible effects are pervasive. What opinion is appropriate?","choices":["Disclaimer of opinion.","Adverse opinion.","Unmodified opinion.","Emphasis-of-matter only."],"ans":"A","exp":"A pervasive inability to obtain evidence leads to a disclaimer."},{"id":"reporting-8x-04","sec":"reporting","topic":"Emphasis Of Matter","conceptId":"reporting-8x-04","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"When is an emphasis-of-matter paragraph appropriate?","choices":["To highlight a properly presented matter fundamental to users’ understanding.","To correct a material misstatement.","To avoid modifying the opinion for a GAAP departure.","To describe all immaterial errors."],"ans":"A","exp":"Emphasis-of-matter paragraphs highlight properly presented or disclosed matters; they do not substitute for modifications."},{"id":"reporting-8x-05","sec":"reporting","topic":"Other Matter","conceptId":"reporting-8x-05","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"An auditor wants to refer to required supplementary information procedures outside the basic statements. What paragraph may be used?","choices":["Other-matter paragraph.","Adverse opinion paragraph.","Management representation paragraph.","Engagement letter paragraph."],"ans":"A","exp":"Other-matter paragraphs address matters other than those presented or disclosed in the financial statements."},{"id":"reporting-8x-06","sec":"reporting","topic":"Going Concern","conceptId":"reporting-8x-06","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Substantial doubt exists and disclosures are adequate. What is the typical reporting effect?","choices":["Adverse opinion automatically.","Unmodified opinion with a going-concern section/emphasis as applicable.","Disclaimer automatically.","No report reference is ever allowed."],"ans":"B","exp":"Adequate going-concern disclosures often result in an unmodified opinion with required reporting emphasis/section."},{"id":"reporting-8x-07","sec":"reporting","topic":"Subsequent Events","conceptId":"reporting-8x-07","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"A condition existed at year-end and new information before report date confirms a material estimate was misstated. What should occur?","choices":["Adjust the financial statements if material.","Ignore because discovered after year-end.","Only disclose in the audit report.","Withdraw immediately without discussion."],"ans":"A","exp":"Recognized subsequent events provide evidence about conditions existing at the balance sheet date and may require adjustment."},{"id":"reporting-8x-08","sec":"reporting","topic":"Comparatives","conceptId":"reporting-8x-08","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"The predecessor auditor’s report is not reissued on comparative statements. What may the successor auditor need to do?","choices":["Make no reference under any circumstances.","Indicate in an other-matter paragraph that prior-period statements were audited by another auditor, if appropriate.","Change the current opinion to adverse.","Audit the predecessor’s workpapers as management."],"ans":"B","exp":"Comparative reporting may require reference to predecessor auditor information when the predecessor report is not presented."},{"id":"reporting-8x-09","sec":"reporting","topic":"Other Information","conceptId":"reporting-8x-09","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"The auditor identifies a material inconsistency in annual report other information. What should the auditor do?","choices":["Ignore it because it is unaudited.","Discuss with management and request correction if necessary.","Change all audit procedures to inventory.","Issue a clean report without consideration."],"ans":"B","exp":"The auditor has responsibilities to read other information and respond to material inconsistencies or misstatements of fact."},{"id":"reporting-8x-10","sec":"reporting","topic":"Written Reps Date","conceptId":"reporting-8x-10","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Written representations should generally be dated as of what date?","choices":["The balance sheet date.","The date of the auditor’s report.","The first day of fieldwork.","The date the engagement letter was signed."],"ans":"B","exp":"Written representations are ordinarily dated as of the auditor’s report date."},{"id":"reporting-8x-11","sec":"reporting","topic":"Unmodified Report","conceptId":"reporting-8x-11","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"Which section communicates management’s responsibility in a standard audit report?","choices":["Responsibilities of Management for the Financial Statements.","Auditor Signature only.","Basis for Adverse Opinion always.","Other-Matter section only."],"ans":"A","exp":"The auditor’s report describes management’s and auditor’s responsibilities in separate sections."},{"id":"reporting-8x-12","sec":"reporting","topic":"Key Audit Matters","conceptId":"reporting-8x-12","difficulty":"Medium","questionType":"Application","sourceType":"Original CPA-style","source":"Original CPA-style question - added v8.2.2","releaseYear":null,"q":"For issuer reporting, key audit matters/critical audit matters relate most closely to what?","choices":["Matters communicated to those charged with governance and involving especially challenging auditor judgment.","All immaterial corrected errors.","Only tax return preparation.","Only items selected by management."],"ans":"A","exp":"CAM/KAM concepts focus on especially challenging, subjective, or complex auditor judgments communicated to governance."}];
const SIMS=[{"id":"sim-ethics-1","sec":"ethics","title":"Independence & Nonaudit Services TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Email from Controller","Proposed Journal Entries","Firm Independence Policy Excerpt","Management Skills Memo"],"exhibitBodies":["DOCUMENT: Email from Controller\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- From: Dana Hill, Controller\nSubject: Year-end assistance\n\nPlease prepare and post year-end entries directly to the general ledger while our controller is on leave.\n- We can sign a representation after posting.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Proposed Journal Entries\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Proposed entries:\nDr Warranty expense 184,000 / Cr Warranty liability 184,000\nDr Allowance for doubtful accounts 96,000 / Cr Accounts receivable 96,000\nDr Legal expense 250,000 / Cr Accrued litigation loss 250,000\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Firm Independence Policy Excerpt\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Policy: The firm may assist with bookkeeping only when management designates a competent person to oversee the work, evaluates results, accepts responsibility, and approves all entries.\n- Firm staff may not authorize, approve, or post transactions.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Management Skills Memo\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- The AP manager understands the accounting system but has not prepared GAAP estimates.\n- The CFO is available to approve final entries after reviewing support.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Classify the requested actions as permitted, permitted with safeguards, or prohibited.","Identify the management-responsibility threat.","State what management must do before auditor assistance is permissible.","Document whether independence is impaired."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-ethics-2","sec":"ethics","title":"Engagement Acceptance and Predecessor Auditor TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Prospective Client Email","Predecessor Auditor Note","Audit Committee Minutes","Acceptance Checklist Excerpt"],"exhibitBodies":["DOCUMENT: Prospective Client Email\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- CFO: We prefer that you not contact our prior auditors.\n- Their revenue cutoff questions delayed last year close.\n- We need a clean start.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Predecessor Auditor Note\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- The predecessor resigned after management refused to adjust December bill-and-hold transactions and will respond only after written client permission.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Audit Committee Minutes\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Audit committee minutes: CFO said the prior auditor was too conservative about revenue and materiality.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Acceptance Checklist Excerpt\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Acceptance policy requires independence, competence, timetable assessment, management integrity evaluation, and predecessor communication.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Identify acceptance risk indicators.","Determine the effect of refusal to permit predecessor communication.","Recommend accept, decline, or delay acceptance.","List acceptance-file documentation."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-risk-1","sec":"risk","title":"Revenue Risk Assessment TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Monthly Sales Analytics","Contract Terms Excerpt","Shipping Cutoff Report","Control Walkthrough Notes"],"exhibitBodies":["DOCUMENT: Monthly Sales Analytics\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Sales: Oct 2.1M\n- Nov 2.3M\n- Dec 4.8M.\n- December gross margin rose from 31% to 46% while units shipped declined 4%.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Contract Terms Excerpt\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Bill-and-hold is allowed only with written customer request, completed goods, separate identification, and goods not available for other orders.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Shipping Cutoff Report\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Nineteen Dec.\n- 29-31 invoices shipped Jan.\n- 3-8.\n- Four bill-and-hold invoices have no written customer request.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Control Walkthrough Notes\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Sales manager can override shipping holds without secondary review\n- system recognizes revenue when invoice is generated.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Identify significant revenue risks.","Map risks to assertions.","Select cutoff and bill-and-hold procedures.","Document fraud-risk consideration."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-risk-2","sec":"risk","title":"IT General Controls and Automated Control Reliance TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Change Management Log","Automated Control Description","Exception Report Sample","IT Manager Explanation"],"exhibitBodies":["DOCUMENT: Change Management Log\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Emergency changes E-114 and E-119 moved to production in December without documented approval or user acceptance testing.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Automated Control Description\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Automated control AP-3 blocks invoices with PO, receiving, and invoice mismatches over $2,500.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Exception Report Sample\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- December exception report shows only two blocked invoices and is generated by the same changed purchasing module.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: IT Manager Explanation\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- IT manager says the changes were minor and approval was documented after the fact.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Evaluate the ITGC deficiency.","Determine whether automated-control reliance remains appropriate.","Identify alternative procedures.","Explain effect on system-generated reports."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-evidence-1","sec":"evidence","title":"Accounts Receivable Confirmation TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["A/R Aging Summary","Confirmation Control Sheet","Subsequent Cash Receipts","Credit Memo Log"],"exhibitBodies":["DOCUMENT: A/R Aging Summary\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- A/R aging: current 3.4M\n- 31-60 820K\n- 61-90 410K\n- over 90 690K.\n- Atlas Retail owes 380K over 120 days.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Confirmation Control Sheet\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Positive confirmations: 30 sent\n- 22 agreed\n- 3 exceptions\n- 5 nonresponses including Atlas Retail.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Subsequent Cash Receipts\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- January receipts: Atlas Retail 0\n- North Bay 112K\n- Camino Foods 95K\n- no receipt for three nonresponses.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Credit Memo Log\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Credit memo CM-448 dated Jan.\n- 6 for 74K relates to goods returned Dec.\n- 29 but processed after year-end.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Determine follow-up procedures for nonresponses.","Evaluate the returned-goods exception.","Identify valuation and cutoff issues.","Document whether allowance testing is required."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-evidence-2","sec":"evidence","title":"Inventory Observation and Cutoff TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Client Count Instructions","Auditor Test Count Sheet","Receiving and Shipping Cutoff","Obsolete Inventory Memo"],"exhibitBodies":["DOCUMENT: Client Count Instructions\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Shipping continued during the count.\n- Count tags were not pre-numbered.\n- Supervisors could create replacement tags.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Auditor Test Count Sheet\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Test counts: Item A-441 floor 118, sheet 181.\n- Item B-220 sheet 75, floor 57.\n- Two tags could not be located.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Receiving and Shipping Cutoff\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Last receiving report RR-8821 dated Dec.\n- 31\n- first after year-end RR-8822 dated Jan.\n- 2.\n- BOL S-774 shipped Dec.\n- 31 but invoiced Jan.\n- 3.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Obsolete Inventory Memo\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Model XG-9 has 640 units on hand, no sales in 10 months, and replacement model released in October.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Identify count process weaknesses.","Determine existence and completeness procedures.","Select cutoff procedures.","Evaluate obsolete inventory reserve testing."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-reporting-1","sec":"reporting","title":"Opinion Modification TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Summary of Uncorrected Misstatements","Management Response","Materiality Memo","Draft Report Planning Note"],"exhibitBodies":["DOCUMENT: Summary of Uncorrected Misstatements\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Inventory is overstated by 1.2M due to obsolete items not written down.\n- Planning materiality is 900K.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Management Response\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- CFO refuses adjustment and says disclosure is enough because recording the entry would violate a debt covenant.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Materiality Memo\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Partner conclusion: misstatement is material but not pervasive and isolated to inventory and cost of sales.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Draft Report Planning Note\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Draft note currently says unmodified opinion expected\n- consider emphasis paragraph for transparency.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Classify GAAP departure or scope limitation.","Determine the appropriate opinion.","Explain why disclosure alone is not enough.","Explain why adverse or disclaimer is not appropriate."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-reporting-2","sec":"reporting","title":"Subsequent Events and Reporting TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Attorney Letter Excerpt","Customer Bankruptcy Notice","Management Disclosure Draft","Subsequent Events Checklist"],"exhibitBodies":["DOCUMENT: Attorney Letter Excerpt\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Attorney letter: product litigation relating to pre-year-end shipments is probable, range 600K-900K, no amount in range better estimate.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Customer Bankruptcy Notice\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Major customer filed Chapter 11 on Jan.\n- 18 due to liquidity problems existing at Dec.\n- 31.\n- Year-end A/R is 520K.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Management Disclosure Draft\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Disclosure draft states ordinary legal matters and customer bankruptcy are not expected to be material\n- no accrual or allowance recorded.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present.","DOCUMENT: Subsequent Events Checklist\nPurpose: Source evidence for the audit simulation. Review this exhibit before preparing the TBS response.\n\nKey information:\n- Procedures include inquiry, reading minutes, legal letters, and testing subsequent cash receipts through report date.\n\nAudit relevance:\n- Identify the assertion, risk, or reporting issue supported by this document.\n- Compare this exhibit with the other exhibits before reaching a conclusion.\n- Do not rely on management explanation alone when contradictory evidence is present."],"tasks":["Classify each subsequent event.","Identify required adjustments or disclosures.","Determine additional evidence needed.","Assess report effect if management refuses correction."],"rubric":["Uses exhibit evidence instead of generic conclusions.","Links facts to the relevant AUD assertion or standard.","Identifies the correct audit response.","Documents a clear conclusion."]},{"id":"sim-ethics-3","sec":"ethics","title":"Independence Threats and Client Request TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Client Service Request","Engagement Team List","Independence Policy","Partner Email"],"exhibitBodies":["DOCUMENT: Client Service Request\nThe controller asks the firm to prepare adjusting entries, approve them in the accounting system, and later audit the balances. Management says it will sign a representation after year-end.","DOCUMENT: Engagement Team List\nThe audit senior assigned to the engagement has a sibling serving as assistant controller. The senior is scheduled to test revenue and receivables.","DOCUMENT: Independence Policy\nFirm personnel may provide technical advice, but management must make decisions, approve entries, and accept responsibility. Covered-member family relationships in key positions require safeguards.","DOCUMENT: Partner Email\nThe partner wants to keep the deadline and asks whether client consent is enough to resolve the threats."],"tasks":["Classify each threat as self-review, familiarity, management participation, or other threat.","Identify which requested services are prohibited or require safeguards.","State the required management responsibilities before any permitted assistance.","Conclude whether the engagement can continue as planned."],"rubric":["Uses exhibit evidence rather than a generic conclusion.","Identifies the relevant assertion, risk, or reporting issue.","Selects an audit response that matches the facts.","Documents a clear final conclusion."]},{"id":"sim-risk-3","sec":"risk","title":"Risk Assessment and Control Design TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Preliminary Analytics","Walkthrough Memo","System Change Notice","Audit Planning Notes"],"exhibitBodies":["DOCUMENT: Preliminary Analytics\nRevenue increased 38% in December while units shipped decreased 6%. Gross margin increased from 29% to 44%.","DOCUMENT: Walkthrough Memo\nSales orders over credit limit can be released by the sales director without secondary review. Revenue is recorded when the invoice is created.","DOCUMENT: System Change Notice\nA new billing module was installed on December 15. User acceptance testing evidence is incomplete.","DOCUMENT: Audit Planning Notes\nManagement bonuses are tied to EBITDA and the company is negotiating a loan renewal in January."],"tasks":["Identify significant risks.","Map each risk to assertions.","Determine whether control reliance is appropriate without additional ITGC evidence.","Recommend further audit procedures."],"rubric":["Uses exhibit evidence rather than a generic conclusion.","Identifies the relevant assertion, risk, or reporting issue.","Selects an audit response that matches the facts.","Documents a clear final conclusion."]},{"id":"sim-evidence-3","sec":"evidence","title":"Receivables Confirmation and Subsequent Receipts TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["A/R Aging","Confirmation Results","Subsequent Cash Receipts","Credit Memo Log"],"exhibitBodies":["DOCUMENT: A/R Aging\nThree customers represent 42% of receivables. Several balances are over 90 days past due.","DOCUMENT: Confirmation Results\nTwo positive confirmations were returned with disputes about goods received after year-end. One customer did not respond.","DOCUMENT: Subsequent Cash Receipts\nPartial payments were received from two customers in January. No payment was received from the largest disputed balance.","DOCUMENT: Credit Memo Log\nCredit memos were issued on January 12 for goods shipped on December 31 but received by customers in January."],"tasks":["Evaluate confirmation exceptions.","Identify follow-up procedures for nonresponses.","Assess valuation and cutoff implications.","Document the conclusion for receivable testing."],"rubric":["Uses exhibit evidence rather than a generic conclusion.","Identifies the relevant assertion, risk, or reporting issue.","Selects an audit response that matches the facts.","Documents a clear final conclusion."]},{"id":"sim-reporting-3","sec":"reporting","title":"Reporting Modification Decision TBS","prompt":"Complete this CPA-style TBS using the individual exhibits. Open each exhibit separately, prepare a response, and self-check against the rubric.","exhibits":["Draft Financial Statements","Uncorrected Misstatement Summary","Management Representation Draft","Disclosure Note"],"exhibitBodies":["DOCUMENT: Draft Financial Statements\nThe draft includes inventory at cost even though lower-of-cost-and-net-realizable-value testing indicates impairment.","DOCUMENT: Uncorrected Misstatement Summary\nThe proposed inventory write-down is material but limited to inventory and cost of goods sold. Management refuses adjustment.","DOCUMENT: Management Representation Draft\nManagement states all material misstatements have been corrected, despite the uncorrected inventory item.","DOCUMENT: Disclosure Note\nNo disclosure describes the inventory valuation issue."],"tasks":["Determine whether the issue is a GAAP departure or scope limitation.","Evaluate materiality and pervasiveness.","Select the appropriate opinion type.","Identify report wording and representation-letter implications."],"rubric":["Uses exhibit evidence rather than a generic conclusion.","Identifies the relevant assertion, risk, or reporting issue.","Selects an audit response that matches the facts.","Documents a clear final conclusion."]}];
const FLASHCARDS=[{"id": "f-ethics-01", "sec": "ethics", "front": "Independence", "back": "Rule: Audit and review engagements require independence in fact and appearance.\n\nExample: Covered member owns client stock; remove the person or dispose of interest before continuing.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-02", "sec": "ethics", "front": "Nonaudit services", "back": "Rule: The auditor cannot assume management responsibilities while providing nonaudit services.\n\nExample: Bookkeeping may be permitted only if management reviews, approves, and accepts responsibility.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-03", "sec": "ethics", "front": "Engagement acceptance", "back": "Rule: Evaluate integrity, independence, competence, and scope before accepting.\n\nExample: Ask the predecessor auditor about management integrity after client permission.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-04", "sec": "ethics", "front": "Audit documentation", "back": "Rule: Workpapers must support procedures performed, evidence obtained, judgments, and conclusions.\n\nExample: A reviewer should see who performed and reviewed work, when, and the conclusion reached.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-05", "sec": "ethics", "front": "Professional skepticism", "back": "Rule: Use a questioning mind and critically assess audit evidence.\n\nExample: Investigate inconsistent explanations about unusual revenue trends.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-06", "sec": "ethics", "front": "Quality management", "back": "Rule: Firm quality policies cover ethics, acceptance, performance, resources, and monitoring.\n\nExample: High-risk engagements may require engagement quality review under firm policy.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-07", "sec": "ethics", "front": "Due care", "back": "Rule: Perform with competence, diligence, supervision, and professional judgment.\n\nExample: Assign qualified staff and supervise/review their work.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-08", "sec": "ethics", "front": "Confidentiality", "back": "Rule: Client information is protected unless consent or professional/legal duty permits disclosure.\n\nExample: Disclosure may be allowed for subpoena, peer review, or ethics investigation.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-09", "sec": "ethics", "front": "Governance communication", "back": "Rule: Significant audit matters should be communicated to those charged with governance.\n\nExample: Report significant deficiencies and material weaknesses to those charged with governance.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-ethics-10", "sec": "ethics", "front": "Engagement letters", "back": "Rule: Written terms reduce misunderstanding about responsibilities and scope.\n\nExample: Identify objective, scope, management responsibilities, auditor responsibilities, and report form.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-01", "sec": "risk", "front": "Understanding the entity", "back": "Rule: Understanding the entity supports risk assessment and audit planning.\n\nExample: Understand revenue streams before assessing revenue recognition risk.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-02", "sec": "risk", "front": "Internal control", "back": "Rule: Understand design and implementation; test operating effectiveness when relying on controls.\n\nExample: Walk through purchase-to-pay to confirm design and implementation.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-03", "sec": "risk", "front": "Risk assessment", "back": "Rule: Assess RMM at both financial statement and assertion levels.\n\nExample: Complex estimates create valuation risk at the assertion level.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-04", "sec": "risk", "front": "Materiality", "back": "Rule: Materiality is judgment-based and considers user needs and circumstances.\n\nExample: Lower materiality may be appropriate when users are sensitive to debt covenants.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-05", "sec": "risk", "front": "Fraud risk", "back": "Rule: Fraud risk requires targeted procedures and skepticism.\n\nExample: Presume revenue-recognition fraud risk unless rebutted and documented.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-06", "sec": "risk", "front": "Analytical procedures", "back": "Rule: Required in planning and final review; substantive use requires precision.\n\nExample: Compare gross margin to a precise expectation and investigate unexpected differences.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-07", "sec": "risk", "front": "IT general controls", "back": "Rule: ITGCs support reliance on automated controls and system-generated reports.\n\nExample: Weak change-management controls can undermine automated invoice matching.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-08", "sec": "risk", "front": "Control environment", "back": "Rule: Tone at the top affects the reliability of the broader control system.\n\nExample: Weak board oversight increases risk of management override.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-09", "sec": "risk", "front": "Significant risks", "back": "Rule: Significant risks require special audit consideration.\n\nExample: A large unusual related-party transaction near year-end may require special audit consideration.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-risk-10", "sec": "risk", "front": "Related-party risks", "back": "Rule: Evaluate relationships, business purpose, authorization, and disclosure.\n\nExample: Inspect minutes and confirmations for undisclosed related-party arrangements.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-01", "sec": "evidence", "front": "Audit evidence", "back": "Rule: Evidence must be sufficient and appropriate.\n\nExample: External confirmations are generally more reliable than internal schedules.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-02", "sec": "evidence", "front": "Confirmations", "back": "Rule: Confirmations obtain evidence directly from knowledgeable third parties.\n\nExample: Positive A/R confirmations request a response whether the customer agrees or disagrees.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-03", "sec": "evidence", "front": "Inventory observation", "back": "Rule: Observation supports existence and condition of inventory.\n\nExample: Trace floor-to-sheet and sheet-to-floor test counts.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-04", "sec": "evidence", "front": "Sampling", "back": "Rule: Sampling risk arises because less than 100% of a population is tested.\n\nExample: Decrease tolerable misstatement and sample size generally increases.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-05", "sec": "evidence", "front": "Substantive analytics", "back": "Rule: Substantive analytics use expected relationships to test account balances.\n\nExample: Estimate payroll using headcount, pay rates, and approved changes.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-06", "sec": "evidence", "front": "Accounts receivable", "back": "Rule: A/R testing commonly addresses existence, valuation, rights, and cutoff.\n\nExample: Confirm balances and test subsequent cash receipts.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-07", "sec": "evidence", "front": "Estimates", "back": "Rule: Evaluate method, assumptions, data, and potential management bias.\n\nExample: Test allowance for doubtful accounts using aging, history, and subsequent collections.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-08", "sec": "evidence", "front": "Fair value", "back": "Rule: Fair value audits focus on valuation methods, inputs, specialists, and disclosure.\n\nExample: Level 3 assumptions require stronger testing and skepticism.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-09", "sec": "evidence", "front": "Subsequent receipts", "back": "Rule: Subsequent receipts can corroborate year-end receivables.\n\nExample: January cash receipts can support December A/R existence and valuation.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-evidence-10", "sec": "evidence", "front": "Cutoff", "back": "Rule: Cutoff testing determines whether transactions are recorded in the correct period.\n\nExample: Match shipping documents around year-end to sales invoices.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-01", "sec": "reporting", "front": "Audit opinion", "back": "Rule: Opinion modification depends on materiality and pervasiveness.\n\nExample: Material but not pervasive GAAP departure generally results in qualified opinion.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-02", "sec": "reporting", "front": "Emphasis-of-matter", "back": "Rule: EOM highlights an appropriately presented/disclosed matter fundamental to users.\n\nExample: Adequately disclosed going-concern uncertainty may require an EOM paragraph.\n\nCPA trap: EOM does not modify the opinion.", "status": "new"}, {"id": "f-reporting-03", "sec": "reporting", "front": "Other-matter paragraph", "back": "Rule: OM discusses matters outside the financial statements relevant to the audit/report.\n\nExample: Use for matters outside the financial statements, such as report-use restriction.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-04", "sec": "reporting", "front": "Going concern", "back": "Rule: Evaluate substantial doubt and adequacy of disclosures.\n\nExample: Recurring losses and debt defaults require substantial doubt evaluation.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-05", "sec": "reporting", "front": "Subsequent events", "back": "Rule: Recognized events adjust; nonrecognized events may disclose.\n\nExample: Customer bankruptcy after year-end may confirm year-end collectibility issues.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-06", "sec": "reporting", "front": "Written representations", "back": "Rule: Management representations complement but do not replace audit evidence.\n\nExample: Representation letter date should ordinarily match the auditor report date.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-07", "sec": "reporting", "front": "Comparative statements", "back": "Rule: Comparatives require attention to prior-period auditor and report treatment.\n\nExample: Prior-period predecessor opinion may be referred to rather than ignored.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-08", "sec": "reporting", "front": "Other information", "back": "Rule: Auditor reads other information for inconsistency or misstatement of fact.\n\nExample: Read annual report information for material inconsistencies with audited statements.\n\nCPA trap: Do not pick an answer based only on management preference, client consent, or vague documentation.", "status": "new"}, {"id": "f-reporting-09", "sec": "reporting", "front": "Scope limitation", "back": "Rule: A scope limitation is inability to obtain sufficient appropriate evidence.\n\nExample: No evidence and no alternative procedures may require qualified opinion or disclaimer.\n\nCPA trap: Do not issue an adverse opinion for a lack of evidence; consider qualified or disclaimer.", "status": "new"}, {"id": "f-reporting-10", "sec": "reporting", "front": "GAAP departure", "back": "Rule: A GAAP departure is a material misstatement from inappropriate accounting/disclosure.\n\nExample: Failure to consolidate a material subsidiary may be pervasive and lead to adverse opinion.\n\nCPA trap: Do not treat a known GAAP departure as a scope limitation.", "status": "new"}];
const READINGS={"ethics":[{"topic":"Independence","rules":["Covered members may not hold direct financial interests in attest clients; material indirect interests also impair independence.","Immediate family employment in a key client position can impair independence and requires removal or other safeguards before work continues.","Client consent or audit committee approval does not cure an independence impairment.","Evaluate threats in fact and appearance before accepting or continuing the engagement."],"traps":["Assuming immaterial direct stock ownership is acceptable.","Using a management representation letter as a safeguard for independence.","Ignoring close family employment because the person is not the CFO."],"example":"Exam alert: If the auditor owns client stock directly, the answer is dispose of the interest or remove the covered member; disclosure is not enough."},{"topic":"Nonaudit services","rules":["The auditor may assist with certain services only when management assumes responsibility, designates a competent individual, evaluates results, and accepts responsibility.","The auditor may not authorize transactions, approve journal entries, make management decisions, or have custody of client assets.","Bookkeeping assistance creates a self-review threat unless management approves entries and the auditor avoids management functions."],"traps":["Letting the auditor post entries directly.","Assuming small clients can waive management responsibility.","Confusing technical advice with making the accounting decision."],"example":"Example: The auditor may prepare a depreciation schedule using client-approved assumptions, but management must select useful lives and approve the final entries."},{"topic":"Engagement acceptance","rules":["Before acceptance, evaluate independence, competence, timetable, predecessor communications, and management integrity.","A prospective client’s refusal to permit predecessor communication is a major warning sign.","Acceptance documentation should show risks identified and the basis for accepting, delaying, or declining."],"traps":["Accepting because audit fees were prepaid.","Skipping predecessor communication when management says the prior auditor was difficult.","Treating acceptance as an administrative step only."],"example":"Example: Refusal to contact the predecessor auditor usually means delay or decline unless the matter is resolved."},{"topic":"Audit documentation","rules":["Documentation should allow an experienced auditor with no prior connection to understand work performed, evidence obtained, and conclusions reached.","After the documentation completion date, changes should be documented with who, when, and why.","Do not delete contradictory evidence merely because the final conclusion changed."],"traps":["Backdating workpapers.","Deleting exceptions after partner review.","Documenting only the conclusion without the evidence and rationale."],"example":"Example: Add a clarifying memo for a changed conclusion; do not erase the original contradictory memo."},{"topic":"Professional skepticism","rules":["Maintain a questioning mind and critically assess audit evidence.","Corroborate management explanations when evidence is inconsistent or unusual.","Fraud risk requires attention to incentives, opportunities, and rationalizations."],"traps":["Accepting vague explanations for unusual fluctuations.","Assuming prior-year experience eliminates fraud risk.","Treating management representations as stronger than external evidence."],"example":"Example: A large unexplained year-end sales increase should trigger follow-up, not automatic acceptance."},{"topic":"Quality management","rules":["Identify the relevant AUD objective for quality management before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating quality management as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For quality management, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Due care","rules":["Identify the relevant AUD objective for due care before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating due care as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For due care, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Confidentiality","rules":["Identify the relevant AUD objective for confidentiality before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating confidentiality as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For confidentiality, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."}],"risk":[{"topic":"Understanding the entity","rules":["Identify the relevant AUD objective for understanding the entity before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating understanding the entity as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For understanding the entity, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Internal control","rules":["Identify the relevant AUD objective for internal control before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating internal control as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For internal control, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Risk assessment","rules":["Identify the relevant AUD objective for risk assessment before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating risk assessment as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For risk assessment, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Materiality","rules":["Identify the relevant AUD objective for materiality before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating materiality as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For materiality, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Fraud risk","rules":["Identify the relevant AUD objective for fraud risk before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating fraud risk as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For fraud risk, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Analytical procedures","rules":["Identify the relevant AUD objective for analytical procedures before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating analytical procedures as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For analytical procedures, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"IT general controls","rules":["Identify the relevant AUD objective for it general controls before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating it general controls as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For it general controls, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Control environment","rules":["Identify the relevant AUD objective for control environment before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating control environment as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For control environment, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."}],"evidence":[{"topic":"Audit evidence","rules":["Sufficient means quantity; appropriate means relevance and reliability.","External evidence obtained directly by the auditor is generally more reliable than internal evidence.","Inquiry alone rarely provides sufficient appropriate evidence for material assertions."],"traps":["Relying solely on management explanations.","Ignoring contradictory evidence.","Assuming more evidence fixes unreliable evidence."],"example":"Example: A bank confirmation received directly by the auditor is more reliable than a client-prepared bank schedule."},{"topic":"Confirmations","rules":["Positive confirmations request a response whether the customer agrees or disagrees; negative confirmations request response only if the customer disagrees.","Nonresponses to positive confirmations require follow-up or alternative procedures.","Exceptions must be investigated to determine whether they are misstatements."],"traps":["Treating nonresponse as agreement.","Letting the client mail and receive confirmations.","Ignoring disputed balances."],"example":"Example: A disputed confirmation should be reconciled to shipping documents, invoices, credit memos, and subsequent cash receipts."},{"topic":"Inventory observation","rules":["Observation provides evidence about existence and condition, not necessarily ownership or valuation.","If the auditor cannot attend the count, alternative procedures may include observing a later count and testing roll-forward.","The auditor should test count instructions, perform test counts, and evaluate obsolete or damaged items."],"traps":["Assuming observation proves inventory is valued correctly.","Using management representation as the only alternative procedure.","Ignoring goods held on consignment."],"example":"Example: Damaged goods observed during the count may indicate a valuation issue requiring lower-of-cost-and-NRV testing."},{"topic":"Sampling","rules":["Identify the relevant AUD objective for sampling before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating sampling as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For sampling, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Substantive analytics","rules":["Identify the relevant AUD objective for substantive analytics before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating substantive analytics as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For substantive analytics, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Accounts receivable","rules":["Identify the relevant AUD objective for accounts receivable before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating accounts receivable as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For accounts receivable, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Estimates","rules":["Identify the relevant AUD objective for estimates before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating estimates as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For estimates, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Fair value","rules":["Identify the relevant AUD objective for fair value before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating fair value as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For fair value, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."}],"reporting":[{"topic":"Audit opinion","rules":["Unmodified opinion is appropriate when statements are fairly presented in accordance with the framework.","A material but not pervasive misstatement usually results in a qualified opinion.","A material and pervasive misstatement results in an adverse opinion; pervasive scope limitation results in a disclaimer."],"traps":["Using emphasis-of-matter to avoid a qualified opinion.","Confusing GAAP departure with scope limitation.","Assuming every material issue is adverse."],"example":"Example: A material inventory GAAP departure limited to inventory is generally qualified; if pervasive, adverse."},{"topic":"Emphasis-of-matter","rules":["Identify the relevant AUD objective for emphasis-of-matter before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating emphasis-of-matter as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For emphasis-of-matter, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Other-matter paragraph","rules":["Identify the relevant AUD objective for other-matter paragraph before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating other-matter paragraph as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For other-matter paragraph, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Going concern","rules":["Evaluate whether conditions raise substantial doubt for a reasonable period.","Assess management’s plans and whether they are probable of being effectively implemented.","If disclosures are adequate, the opinion may remain unmodified with required going-concern language."],"traps":["Issuing adverse solely because substantial doubt exists.","Ignoring events after year-end that affect liquidity.","Relying on unsupported management plans."],"example":"Example: A signed financing agreement may mitigate substantial doubt; a vague plan to seek financing generally does not."},{"topic":"Subsequent events","rules":["Recognized subsequent events provide evidence about conditions existing at the balance sheet date and may require adjustment.","Nonrecognized subsequent events relate to conditions arising after year-end and may require disclosure.","Auditor responsibilities differ before and after report release."],"traps":["Adjusting for events that arose after year-end.","Ignoring information learned before report date.","Confusing dual dating with changing all report procedures."],"example":"Example: Bankruptcy of a customer due to pre-year-end financial difficulty may require adjustment to receivables."},{"topic":"Written representations","rules":["Written representations are required and ordinarily dated as of the auditor’s report date.","Representations complement but do not replace other audit evidence.","Refusal to provide representations may create a scope limitation."],"traps":["Using reps as substitute for confirmations.","Accepting a rep letter dated weeks before the report date.","Ignoring inconsistent representations."],"example":"Example: Management’s statement that all misstatements are corrected conflicts with an uncorrected material misstatement and must be resolved."},{"topic":"Comparative statements","rules":["Identify the relevant AUD objective for comparative statements before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating comparative statements as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For comparative statements, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."},{"topic":"Other information","rules":["Identify the relevant AUD objective for other information before selecting procedures.","Match the procedure to the assertion, risk, or reporting decision rather than relying on a generic checklist.","Corroborate management explanations with independent or internally controlled evidence when the matter is material.","Document the facts, evidence obtained, and conclusion clearly enough for review."],"traps":["Treating other information as a memorization-only topic.","Choosing a report paragraph or procedure that does not match materiality and pervasiveness.","Ignoring contradictory evidence because management provided a representation."],"example":"Exam example: For other information, first identify the assertion or reporting issue, then select the procedure or conclusion that directly responds to that risk."}]};


// v8.2.3 targeted content expansion: additional original CPA-style MCQs and flashcards.
(function addV823Content(){
  const configs={
    ethics:{prefix:'ethx',topics:['Independence','Nonaudit services','Engagement acceptance','Documentation','Professional skepticism','Quality management','Confidentiality','Communication with governance'],rule:'select the response that protects independence, due care, and audit quality before continuing'},
    risk:{prefix:'riskx',topics:['Fraud risk','Revenue recognition','Internal control','IT general controls','Materiality','Related parties','Analytical procedures','Significant risks'],rule:'identify the risk, assertion, and planned audit response before relying on evidence'},
    evidence:{prefix:'evidx',topics:['Confirmations','Inventory observation','Sampling','Estimates','Subsequent receipts','Cutoff','Specialists','Audit evidence reliability'],rule:'obtain sufficient appropriate evidence that directly addresses the assertion'},
    reporting:{prefix:'repx',topics:['Qualified opinion','Adverse opinion','Disclaimer','Emphasis-of-matter','Going concern','Subsequent events','Written representations','Other information'],rule:'match the report effect to materiality, pervasiveness, evidence obtained, and disclosure adequacy'}
  };
  const difficulties=['Easy','Medium','Hard'];
  const scenarios=[
    ['Management provides an explanation that conflicts with independent evidence near year-end.', 'Corroborate the explanation with additional audit evidence and document the conclusion.', 'Accept the explanation because management is responsible for the financial statements.', 'Reduce testing because the explanation appears reasonable.', 'Wait for the representation letter and perform no other procedures.', 'A'],
    ['A reviewer finds a conclusion but cannot identify the evidence that supports it.', 'Add documentation showing the procedures, evidence, timing, preparer/reviewer, and conclusion.', 'Delete the workpaper because incomplete documentation is worse than no documentation.', 'Rely on oral explanation after report release.', 'Issue the report because documentation is not part of audit evidence.', 'A'],
    ['The audit team identifies a material exception that management says is not important.', 'Evaluate materiality, obtain evidence, and require correction or appropriate reporting response.', 'Ignore the exception if management signs a representation.', 'Move the exception to next year because it is isolated.', 'Use an emphasis paragraph to avoid additional procedures.', 'A'],
    ['A control appears well designed but implementation evidence is incomplete.', 'Perform procedures to confirm implementation before relying on the control.', 'Rely on the control because design is sufficient.', 'Reduce substantive procedures because controls exist on paper.', 'Treat the control as operating effectively for the full year.', 'A'],
    ['A material account balance depends on a complex estimate with optimistic assumptions.', 'Test the method, data, assumptions, and possible management bias.', 'Accept the estimate because estimates are management judgments.', 'Avoid testing because estimates cannot be verified precisely.', 'Use the prior-year estimate without considering current conditions.', 'A']
  ];
  Object.entries(configs).forEach(([sec,cfg])=>{
    cfg.topics.forEach((topic,ti)=>{
      for(let i=0;i<3;i++){
        let s=scenarios[(ti+i)%scenarios.length];
        let id=`${cfg.prefix}-${String(ti+1).padStart(2,'0')}-${i+1}`;
        if(!QUESTIONS.some(q=>q.id===id)) QUESTIONS.push({id,sec,topic,conceptId:`${sec}-${topic.toLowerCase().replace(/[^a-z0-9]+/g,'-')}-${i+1}`,difficulty:difficulties[(ti+i)%3],questionType:i===0?'Application':i===1?'Analysis':'Professional Judgment',sourceType:'Original CPA-style',source:'Original CPA-style question - added v8.2.3',releaseYear:null,q:`${topic}: ${s[0]} What should the auditor do next?`,choices:[s[1],s[2],s[3],s[4]],ans:s[5],exp:`For ${topic}, the CPA-style response is to ${cfg.rule}. The correct choice responds to the risk with evidence, documentation, or appropriate reporting rather than relying only on management preference.`});
      }
      let fid=`fc-${cfg.prefix}-${String(ti+1).padStart(2,'0')}`;
      if(!FLASHCARDS.some(f=>f.id===fid)) FLASHCARDS.push({id:fid,sec,front:topic,back:`Rule: For ${topic}, ${cfg.rule}.\n\nExample: When facts conflict or evidence is incomplete, perform targeted procedures and document the conclusion.\n\nCPA trap: Do not choose client consent, a representation letter, or generic documentation as a substitute for sufficient appropriate evidence.`,status:'new'});
    });
  });
})();

const AREA_VIEWS=['MCQs','Simulations','Flashcards','Readings'];
const GLOBAL_VIEWS=['Dashboard','Missed Log','Calendar','Exam Mode','System Health','Backup & Restore'];
const NAV=['Dashboard','MCQs','Simulations','Flashcards','Readings','Missed Log','Calendar','Exam Mode','System Health','Backup & Restore','Dark Mode'];
const $=id=>document.getElementById(id);
function freshState(){return {version:APP_VERSION,section:'ethics',view:'Dashboard',answered:{},missed:{},progress:{},flash:{},flashIndex:{},showBack:false,sim:{},quiz:null,quizHistory:{},examRun:null,dark:localStorage.dark==='1',examDate:''};}
let state={...freshState(),...JSON.parse(localStorage.getItem(STORAGE_KEY)||'{}')};
const LOADED_VERSION=state.version||'';
if(state.examDate==='2026-08-31') state.examDate='';
if(LOADED_VERSION!==APP_VERSION){state.examRun=null;state.quiz=null;}
function save(){state.version=APP_VERSION;localStorage.setItem(STORAGE_KEY,JSON.stringify(state));}
function secObj(id){return SECTIONS.find(s=>s.id===id)||SECTIONS[0]}
function sectionName(id){if(id==='mixed')return 'Mixed'; let s=secObj(id); return s.name;}
function areaQs(sec=state.section){return QUESTIONS.filter(q=>q.sec===sec)}
function areaSims(sec=state.section){return SIMS.filter(s=>s.sec===sec)}
function areaFlash(sec=state.section){return FLASHCARDS.filter(f=>f.sec===sec)}
function today(){return new Date().toISOString().slice(0,10)}
function logActivity(type,sec,detail){let d=today();state.progress[d]=state.progress[d]||[];state.progress[d].push({time:new Date().toLocaleTimeString(),type,sec,detail});}
function render(){document.body.classList.toggle('dark',!!state.dark);renderSections();renderNav();let v=state.view;if(v==='Dashboard')dashboard();else if(v==='MCQs')mcqs();else if(v==='Simulations')sims();else if(v==='Flashcards')flash();else if(v==='Readings')read();else if(v==='Missed Log')missed();else if(v==='Calendar')calendar();else if(v==='Exam Mode')exam();else if(v==='System Health')systemHealth();else if(v==='Backup & Restore')backup();}
function renderSections(){let active=AREA_VIEWS.includes(state.view);$('sections').innerHTML=SECTIONS.map(s=>`<button ${active?'':'disabled'} class="${state.section===s.id&&active?'active':''}" onclick="state.section='${s.id}';save();render()"><span class="area-title">Area ${s.roman}</span><span class="area-name">${s.name}</span></button>`).join('');}
function renderNav(){$('nav').innerHTML=NAV.map(v=>`<button class="${state.view===v?'active':''}" onclick="${v==='Dark Mode'?'toggleDark()':`state.view='${v}';save();render()`}">${v}</button>`).join('');}
function pct(n,d){return d?Math.round(n/d*100):0}
function dashboard(){let answered=Object.values(state.answered);let correct=answered.filter(a=>a.correct).length;let hasDate=!!state.examDate;let d=hasDate?Math.ceil((new Date(state.examDate+'T00:00:00')-new Date())/86400000):null;$('app').innerHTML=`<div class="card hero"><h2>CPA AUD Command Center</h2><div class="grid"><div><b>Running Score</b><div class="metric">${pct(correct,answered.length)}%</div><p class="muted">Based on attempted MCQs.</p></div><div><b>Days to Exam</b><div class="metric">${hasDate?d:'—'}</div><p><span class="pill">${hasDate?state.examDate:'No exam date set'}</span></p><button onclick="state.view='Calendar';save();render()">Set Exam Date</button></div><div><b>Missed Questions</b><div class="metric">${Object.keys(state.missed).length}</div><p class="muted">Automatically captured for review.</p></div><div><b>Today's Activity</b><div class="metric">${(state.progress[today()]||[]).length}</div><p class="muted">Logged actions today.</p></div></div></div><div class="card"><h2>Blueprint Areas</h2><div class="grid">${SECTIONS.map(s=>{let qs=QUESTIONS.filter(q=>q.sec===s.id), done=qs.filter(q=>state.answered[q.id]).length, cor=qs.filter(q=>state.answered[q.id]?.correct).length;return `<div class="card"><span class="pill">Area ${s.roman}</span><h3>${s.name}</h3><div class="metric">${pct(cor,done)}%</div><div class="bar"><span style="width:${pct(done,qs.length)}%"></span></div><p class="muted">${qs.length} MCQs · ${areaSims(s.id).length} simulations · ${areaFlash(s.id).length} flashcards · Weight: ${s.weight}</p><div class="actions"><button onclick="state.section='${s.id}';state.view='MCQs';save();render()">MCQs</button><button onclick="state.section='${s.id}';state.view='Simulations';save();render()">Simulations</button></div></div>`}).join('')}</div></div>`}

function getFreshQuestionPool(sec,n,ids=null){
  let pool=(ids?ids.map(id=>QUESTIONS.find(q=>q.id===id)).filter(Boolean):QUESTIONS.filter(q=>q.sec===sec));
  if(ids) return pool.sort(()=>Math.random()-.5);
  state.quizHistory=state.quizHistory||{};
  let h=state.quizHistory[sec]||{seen:[]};
  let seen=new Set(h.seen||[]);
  let unseen=pool.filter(q=>!seen.has(q.id));
  if(unseen.length<n){h.seen=[];seen=new Set();unseen=pool.slice();}
  state.quizHistory[sec]=h;
  return unseen.sort(()=>Math.random()-.5);
}
function markQuizSeen(sec,ids){
  state.quizHistory=state.quizHistory||{};
  let h=state.quizHistory[sec]||{seen:[]};
  let seen=new Set(h.seen||[]);
  ids.forEach(id=>seen.add(id));
  h.seen=[...seen];
  state.quizHistory[sec]=h;
}

function mcqs(){let qs=areaQs();$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — MCQs</h2><p class="muted">Questions are numbered 1…N and stop exactly at the selected sample size.</p><div class="actions">${[5,10,20].map(n=>`<button ${qs.length<n?'disabled title="Only '+qs.length+' questions available"':''} class="${n<=10?'primary':''}" onclick="startQuiz(${n})">Start ${n}</button>`).join('')}<button onclick="startQuiz(${qs.length})">All Area Questions</button></div><p><b>${qs.length}</b> available questions in this area. Each item includes source, difficulty, type, topic, and area metadata.</p></div>`}
function startQuiz(n,ids=null){let sec=state.section;let pool=getFreshQuestionPool(sec,n,ids);if(!ids&&n<pool.length){let seenConcept=new Set(), unique=[];pool.forEach(q=>{let c=q.conceptId||q.topic;if(!seenConcept.has(c)){seenConcept.add(c);unique.push(q);}});if(unique.length>=n) pool=unique;}let selected=pool.slice(0,Math.min(n,pool.length));if(!selected.length){alert('No questions available.');return;}if(!ids)markQuizSeen(sec,selected.map(q=>q.id));state.quiz={ids:selected.map(q=>q.id),idx:0,answered:false,selected:null,score:0};logActivity('Quiz Started',selected[0].sec,`${selected.length} questions`);save();quizQuestion();}
function qMeta(q){let src=q.sourceType==='CPA Released' ? `CPA Released Question · ${q.releaseYear||'Year needed'}` : q.sourceType;return `${src} · ${q.difficulty} · ${q.questionType} · ${q.topic}`;}
function quizQuestion(){let ids=state.quiz.ids, idx=state.quiz.idx, q=QUESTIONS.find(x=>x.id===ids[idx]);if(!q)return quizDone();$('app').innerHTML=`<div class="card"><h2>${sectionName(q.sec)} — MCQ</h2><p class="muted">Question ${idx+1} of ${ids.length} · ${qMeta(q)}</p><h3>${q.q}</h3>${q.choices.map((c,i)=>{let L=String.fromCharCode(65+i);let cls=state.quiz.answered?(L===q.ans?'correct':(state.quiz.selected===L?'wrong':'')):'';return `<button class="choice ${cls}" onclick="answer('${L}')"><b>${L}.</b> ${c}</button>`}).join('')}<div>${state.quiz.answered?`<p><b>${state.quiz.selected===q.ans?'Correct':'Incorrect'}.</b> ${q.exp}</p><button class="primary" onclick="nextQ()">${idx+1===ids.length?'Finish':'Next Question'}</button>`:''}</div></div>`}
function answer(letter){if(state.quiz.answered)return;let q=QUESTIONS.find(x=>x.id===state.quiz.ids[state.quiz.idx]);let correct=letter===q.ans;state.quiz.answered=true;state.quiz.selected=letter;if(correct)state.quiz.score++;state.answered[q.id]={correct,selected:letter,date:new Date().toISOString(),sec:q.sec,topic:q.topic};if(!correct){state.missed[q.id]=state.missed[q.id]||{id:q.id,sec:q.sec,topic:q.topic,q:q.q,choices:q.choices,ans:q.ans,exp:q.exp,count:0,reviewed:false};state.missed[q.id].count++;state.missed[q.id].lastAnswer=letter;state.missed[q.id].lastMissed=new Date().toISOString()}logActivity(correct?'MCQ Correct':'MCQ Missed',q.sec,`${state.quiz.idx+1} of ${state.quiz.ids.length}`);save();quizQuestion();}
function nextQ(){state.quiz.idx++;state.quiz.answered=false;state.quiz.selected=null;save();state.quiz.idx>=state.quiz.ids.length?quizDone():quizQuestion();}
function quizDone(){let total=state.quiz.ids.length, score=state.quiz.score, p=pct(score,total);state.quiz=null;save();$('app').innerHTML=`<div class="card"><h2>Sample Completed</h2><p class="metric">${p}%</p><p>${score} correct of ${total}. The sample stopped at Question ${total} of ${total}.</p><button class="primary" onclick="state.view='MCQs';save();render()">Back to MCQs</button></div>`}
function sims(){let list=areaSims();$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Simulations</h2><p class="muted">Use Open Exhibits, complete the response, save, and self-check.</p></div>`+list.map(s=>`<div class="card"><h3>${s.title}</h3><p>${s.prompt}</p><button onclick="openExhibits('${s.id}')">Open Exhibits</button><div id="ex-${s.id}" style="display:none">${s.exhibitBodies.map((b,i)=>`<pre><b>${s.exhibits[i]}</b>\n${b}</pre>`).join('')}</div><h4>Tasks</h4><ol>${s.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="sim-${s.id}">${(state.sim[s.id]||{}).text||''}</textarea><div id="rubwrap-${s.id}" style="display:none"><h4>Self-check rubric</h4>${s.rubric.map((r,i)=>`<label><input type="checkbox" id="${s.id}-${i}" ${(state.sim[s.id]||{}).checks?.[i]?'checked':''}> ${r}</label><br>`).join('')}<div id="rub-${s.id}" class="muted"><ol>${s.rubric.map(r=>`<li>${r}</li>`).join('')}</ol></div></div><br><button class="primary" onclick="saveSim('${s.id}')">Save Response</button><button id="rubbtn-${s.id}" onclick="showRubric('${s.id}')">Show Rubric</button></div>`).join('')}
function exhibitHtml(sim){return `<div class="exhibit-modal" role="dialog" aria-modal="true" aria-label="Simulation exhibits"><div class="exhibit-window"><div class="exhibit-head"><div><b>${sim.title} — Exhibits</b><div class="muted">Open each exhibit individually, then close the exhibit window to complete the TBS.</div></div><button class="primary" onclick="closeExhibits()">Close Exhibits</button></div><div class="exhibit-layout"><aside class="exhibit-tabs">${sim.exhibitBodies.map((b,i)=>`<button class="exhibit-tab ${i===0?'active':''}" onclick="showExhibit(${i})">Exhibit ${i+1}<br><span>${sim.exhibits[i]}</span></button>`).join('')}</aside><section class="exhibit-view">${sim.exhibitBodies.map((b,i)=>`<article class="exhibit-doc" data-exhibit-index="${i}" style="display:${i===0?'block':'none'}"><h3>Exhibit ${i+1}: ${sim.exhibits[i]}</h3><pre>${b}</pre></article>`).join('')}</section></div></div></div>`}
function showExhibit(i){document.querySelectorAll('.exhibit-doc').forEach((el,idx)=>el.style.display=idx===i?'block':'none');document.querySelectorAll('.exhibit-tab').forEach((el,idx)=>el.classList.toggle('active',idx===i));}
function openExhibits(id){let sim=SIMS.find(s=>s.id===id);if(!sim){alert('Exhibits are unavailable for this simulation.');return;}let old=$('exhibit-root');if(old)old.remove();let root=document.createElement('div');root.id='exhibit-root';root.innerHTML=exhibitHtml(sim);document.body.appendChild(root);let closeBtn=root.querySelector('button');if(closeBtn)closeBtn.focus();}
function closeExhibits(){let root=$('exhibit-root');if(root)root.remove();}
function toggleExhibits(id){openExhibits(id)}
function showRubric(id){let wrap=$('rubwrap-'+id),btn=$('rubbtn-'+id);if(!wrap)return;let hidden=wrap.style.display==='none'||wrap.style.display==='';wrap.style.display=hidden?'block':'none';if(btn)btn.textContent=hidden?'Hide Rubric':'Show Rubric';}
function saveSim(id){let sim=SIMS.find(s=>s.id===id);let checks=sim.rubric.map((_,i)=>$(`${id}-${i}`).checked);state.sim[id]={text:$(`sim-${id}`).value,checks,date:new Date().toISOString()};logActivity('Simulation Saved',sim.sec,sim.title);save();alert('Simulation saved. Self-check: '+checks.filter(Boolean).length+' of '+checks.length);}
function flash(){let fs=areaFlash();let idx=Math.max(0,Math.min(state.flashIndex[state.section]||0,fs.length-1));let f=fs[idx];let status=state.flash[f.id]||'new';$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Flashcards</h2><p class="muted">Card ${idx+1} of ${fs.length}</p><div class="card"><h3>${f.front}</h3><p>${state.showBack?f.back:'Tap Flip Card to show the answer.'}</p><p><span class="pill" title="Flashcard review status label">${status==='new'?'Unreviewed':status}</span></p><div class="actions"><button onclick="state.showBack=!state.showBack;save();flash()">Flip Card</button><button ${idx===0?'disabled':''} onclick="flashMove(-1)">Previous</button><button ${idx===fs.length-1?'disabled':''} onclick="flashMove(1)">Next</button><button onclick="setFlashStatus('${f.id}','learning')">Learning</button><button class="primary" onclick="setFlashStatus('${f.id}','mastered')">Mastered</button></div></div></div>`}
function flashMove(delta){let fs=areaFlash();let idx=Math.max(0,Math.min((state.flashIndex[state.section]||0)+delta,fs.length-1));state.flashIndex[state.section]=idx;state.showBack=false;logActivity('Flashcard Reviewed',state.section,fs[idx].front);save();flash();}
function setFlashStatus(id,status){state.flash[id]=status;logActivity('Flashcard '+status,state.section,id);save();flash();}
function read(){let rows=READINGS[state.section]||[];logActivity('Reading Opened',state.section,sectionName(state.section));$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Readings</h2><p class="muted">Expanded outline-level review notes. Use with MCQs and simulations.</p></div>`+rows.map(r=>`<div class="card"><h3>${r.topic}</h3><h4>Key rules</h4><ul>${r.rules.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Common CPA traps</h4><ul>${r.traps.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Exam example</h4><p>${r.example}</p></div>`).join('')}
function missed(){let list=Object.values(state.missed).sort((a,b)=>new Date(b.lastMissed)-new Date(a.lastMissed));let areas=['all',...SECTIONS.map(s=>s.id)];let filter=state.missedFilter||'all';let filtered=filter==='all'?list:list.filter(m=>m.sec===filter);$('app').innerHTML=`<div class="card"><h2>Missed Questions Log</h2><p class="muted">Review missed items with the original choices, your last answer, the correct answer, and explanation.</p><div class="actions">${areas.map(a=>`<button class="${filter===a?'primary':''}" onclick="state.missedFilter='${a}';save();missed()">${a==='all'?'All':sectionName(a)}</button>`).join('')}</div><div class="actions"><button onclick="retakeMissed(10,false)">Retake 10 Missed</button><button onclick="retakeMissed(999,false)">Retake All Missed</button><button class="primary" onclick="retakeMissed(10,true)">Take 10 Related Questions</button></div></div>`+(filtered.length?filtered.map(m=>{let q=QUESTIONS.find(x=>x.id===m.id)||m;let choices=(q.choices||m.choices||[]).map((c,i)=>{let L=String.fromCharCode(65+i);let cls=L===m.ans?'correct':(L===m.lastAnswer?'wrong':'');return `<div class="choice ${cls}"><b>${L}.</b> ${c}</div>`}).join('');return `<div class="card"><b>${sectionName(m.sec)}</b> · ${m.topic} · missed ${m.count} time(s) ${m.reviewed?'<span class="pill">Reviewed</span>':''}<h3>${m.q}</h3>${choices}<p><b>Your last answer:</b> ${m.lastAnswer||'—'} &nbsp; <b>Correct answer:</b> ${m.ans}</p><p><b>Explanation:</b> ${m.exp}</p><div class="actions"><button onclick="startQuiz(1,['${m.id}'])">Retry Question</button><button onclick="markMissedReviewed('${m.id}')">Mark Reviewed</button><button class="danger" onclick="removeMissed('${m.id}')">Remove from Log</button></div></div>`}).join(''):'<div class="card">No missed questions yet for this filter.</div>')}
function markMissedReviewed(id){if(state.missed[id])state.missed[id].reviewed=true;save();missed();}
function removeMissed(id){delete state.missed[id];save();missed();}
function retakeMissed(n,related){let miss=Object.values(state.missed);let ids=miss.map(m=>m.id);if(related){let secs=new Set(miss.map(m=>m.sec)), topics=new Set(miss.map(m=>m.topic));let rel=QUESTIONS.filter(q=>secs.has(q.sec)&&(topics.has(q.topic)||ids.includes(q.id)));if(rel.length<10) rel=QUESTIONS.filter(q=>secs.has(q.sec));ids=rel.map(q=>q.id);}startQuiz(n,ids);}
function dailySummary(entries){let mcq=entries.filter(e=>e.type.startsWith('MCQ'));let correct=entries.filter(e=>e.type==='MCQ Correct').length;let sims=entries.filter(e=>e.type==='Simulation Saved').length;let reads=entries.filter(e=>e.type==='Reading Opened').length;let flash=entries.filter(e=>e.type.startsWith('Flashcard')).length;return `<div class="grid"><div><b>Total Activities</b><div class="metric">${entries.length}</div></div><div><b>MCQ Accuracy</b><div class="metric">${pct(correct,mcq.length)}%</div></div><div><b>Simulations</b><div class="metric">${sims}</div></div><div><b>Readings / Flashcards</b><div class="metric">${reads}/${flash}</div></div></div>`}
function studyPlan(){let base=['Ethics + independence MCQs','Risk assessment readings + 10 MCQs','Evidence: confirmations/inventory + 10 MCQs','Reporting readings + opinion/modification MCQs','Mixed MCQ review + missed log','Two simulations with exhibits','Final mixed set + flashcards'];let start=new Date();let rows=[];for(let i=0;i<7;i++){let d=new Date(start);d.setDate(start.getDate()+i);rows.push({date:d.toISOString().slice(0,10),task:base[i%base.length]});}return rows;}
function setExamDate(){let v=$('exam-date-input').value;if(!v){alert('No new date entered. Existing exam date was preserved. Use Clear to remove it.');return;}state.examDate=v;logActivity('Exam Date Updated','mixed',state.examDate);save();render();}
function clearExamDate(){state.examDate='';logActivity('Exam Date Cleared','mixed','No exam date set');save();render();}
function calendar(){let dates=Object.keys(state.progress).sort().reverse();let hasDate=!!state.examDate;let d=hasDate?Math.ceil((new Date(state.examDate+'T00:00:00')-new Date())/86400000):null;let plan=studyPlan();$('app').innerHTML=`<div class="card"><h2>Study Calendar</h2><p class="muted">Set your exam date and use the 7-day planner with the daily progress log below. The app no longer uses a hardcoded August 31 date.</p><div class="actions"><label>Exam date <input id="exam-date-input" type="date" value="${state.examDate||''}"></label><button class="primary" onclick="setExamDate()">Save Exam Date</button><button onclick="clearExamDate()">Clear</button></div><p><span class="pill">${hasDate?'Exam date: '+state.examDate:'No exam date set'}</span> <span class="pill">${hasDate?'Days remaining: '+d:'Days remaining: —'}</span></p></div><div class="card"><h2>7-Day Study Plan</h2><table><tr><th>Date</th><th>Recommended focus</th></tr>${plan.map(x=>`<tr><td>${x.date}</td><td>${x.task}</td></tr>`).join('')}</table></div><div class="card"><h2>Daily Progress Log</h2><p class="muted">Daily summary plus activity detail.</p></div>`+(dates.length?dates.map(d=>{let entries=state.progress[d];return `<div class="card"><h3>${d}</h3>${dailySummary(entries)}<table><tr><th>Time</th><th>Activity</th><th>Area</th><th>Detail</th></tr>${entries.map(e=>`<tr><td>${e.time}</td><td>${e.type}</td><td>${sectionName(e.sec)}</td><td>${e.detail}</td></tr>`).join('')}</table></div>`}).join(''):'<div class="card">No activity yet.</div>')}

function examTbsPreview(sids,locked=true){let sims=sids.map(id=>SIMS.find(s=>s.id===id)).filter(Boolean);return `<div class="card"><h3>Task-Based Simulations ${locked?'🔒 Locked until MCQs are completed':''}</h3><p class="muted">The simulations are part of this exam set and will unlock after the MCQ testlet.</p>${sims.length?`<ul>${sims.map(s=>`<li><b>${s.title}</b> · ${sectionName(s.sec)} · ${locked?'Complete MCQs first to begin.':'Available now.'}</li>`).join('')}</ul>`:'<p>No simulations selected.</p>'}</div>`;}
function sampleSimIds(n){return SIMS.slice(0,Math.min(n,SIMS.length)).map(s=>s.id);}

function exam(){let totalQs=QUESTIONS.length,totalSims=SIMS.length;let active=state.examRun;let activeCard=active?`<div class="card"><h3>Active exam in progress</h3><p class="muted">${active.label||'Exam'} · ${active.phase==='tbs'?'Simulation phase':'MCQ question '+((active.idx||0)+1)+' of '+active.ids.length}. You may resume it or discard it to choose a new Sample, Partial, or Full Exam.</p><div class="actions"><button class="primary" onclick="resumeExam()">Resume Active Exam</button><button class="danger" onclick="discardExam()">Discard Active Exam</button></div>${examTbsPreview(active.sids,active.phase!=='tbs')}</div>`:'';$('app').innerHTML=`<div class="card"><h2>Exam Mode</h2><p class="muted">CPA-style simulator: MCQs are presented first. The TBS section is visible from the beginning but remains locked until MCQs are complete.</p></div>${activeCard}<div class="grid"><div class="card"><h3>Sample Test</h3><p><b>10 MCQs + 1 TBS</b></p>${examTbsPreview(sampleSimIds(1),true)}<button class="primary" onclick="startExam(10,1,'Sample Test')">Start Sample Test</button></div><div class="card"><h3>Partial Exam</h3><p><b>20 MCQs + 2 TBSs</b></p>${examTbsPreview(sampleSimIds(2),true)}<button class="primary" onclick="startExam(20,2,'Partial Exam')">Start Partial Exam</button></div><div class="card"><h3>Full Exam Set</h3><p><b>${totalQs} MCQs + ${totalSims} TBSs</b></p>${examTbsPreview(sampleSimIds(totalSims),true)}<button class="warn" onclick="startExam(${totalQs},${totalSims},'Full Exam Set')">Start Full Exam Set</button></div></div><div class="card"><ol><li>MCQ testlet first.</li><li>Simulation testlets unlock after MCQs.</li><li>Final report shows MCQ score by area and TBS completion.</li></ol></div>`}
function resumeExam(){examRun();}
function discardExam(){if(confirm('Discard the active exam and return to the exam menu?')){state.examRun=null;save();exam();}}
function startExam(n,tbs,label){let ids=QUESTIONS.slice().sort(()=>Math.random()-.5).slice(0,Math.min(n,QUESTIONS.length)).map(q=>q.id);let sids=SIMS.slice().sort(()=>Math.random()-.5).slice(0,Math.min(tbs,SIMS.length)).map(s=>s.id);state.examRun={ids,sids,idx:0,simIdx:0,score:0,answered:false,selected:null,responses:{},simResponses:{},phase:'mcq',label:label||'Exam'};logActivity('Exam Mode Started','mixed',`${label||'Exam'}: ${ids.length} MCQs + ${sids.length} TBS`);save();examRun();}
function examRun(){let ex=state.examRun;if(!ex)return exam();if(!ex.responses)ex.responses={};if(ex.phase==='tbs')return examTbs();if(ex.idx>=ex.ids.length){ex.phase='tbs';ex.simIdx=0;save();return examTbs();}let q=QUESTIONS.find(x=>x.id===ex.ids[ex.idx]);let prior=ex.responses[q.id];ex.answered=!!prior;ex.selected=prior?prior.selected:null;let nextLabel=ex.idx+1===ex.ids.length?(ex.sids.length?'Continue to Simulations':'Submit Exam'):'Next';$('app').innerHTML=`<div class="card"><div class="actions"><button onclick="exam()">Back to Exam Menu</button><button class="danger" onclick="discardExam()">Discard Exam</button></div><h2>Exam Mode — ${ex.label||'Exam'} MCQ Testlet</h2><p class="muted">Question ${ex.idx+1} of ${ex.ids.length} · ${sectionName(q.sec)} · ${qMeta(q)}</p><h3>${q.q}</h3>${q.choices.map((c,i)=>{let L=String.fromCharCode(65+i);let picked=ex.selected===L?' selected recorded':'';return `<button type="button" class="choice exam-choice${picked}" data-letter="${L}" onclick="examAnswer('${L}')"><b>${L}.</b> ${c}</button>`}).join('')}<p class="muted">Exam mode records your selection and hides explanations until the final report.</p>${ex.answered?`<p class="exam-status">Answer recorded: ${ex.selected}. You may continue.</p><button class="primary" onclick="examNext()">${nextLabel}</button>`:`<p class="muted">Select one answer to continue.</p><button class="primary" disabled>${nextLabel}</button>`}</div>${examTbsPreview(ex.sids,true)}`}
function examAnswer(letter){let ex=state.examRun;if(!ex||ex.phase!=='mcq')return;let q=QUESTIONS.find(x=>x.id===ex.ids[ex.idx]);if(!q)return;let previous=ex.responses&&ex.responses[q.id];if(previous)return;let correct=letter===q.ans;ex.responses=ex.responses||{};ex.responses[q.id]={selected:letter,correct,date:new Date().toISOString(),sec:q.sec,topic:q.topic};ex.answered=true;ex.selected=letter;ex.score=Object.values(ex.responses).filter(r=>r.correct).length;state.answered[q.id]={correct,selected:letter,date:new Date().toISOString(),sec:q.sec,topic:q.topic};if(!correct){state.missed[q.id]=state.missed[q.id]||{id:q.id,sec:q.sec,topic:q.topic,q:q.q,choices:q.choices,ans:q.ans,exp:q.exp,count:0,reviewed:false};state.missed[q.id].count++;state.missed[q.id].lastAnswer=letter;state.missed[q.id].lastMissed=new Date().toISOString();}save();examRun();}
function examNext(){let ex=state.examRun;if(!ex)return exam();let qid=ex.ids[ex.idx];if(!ex.responses||!ex.responses[qid]){alert('Please select an answer before continuing.');return;}ex.idx++;ex.answered=false;ex.selected=null;save();examRun();}
function examTbs(){let ex=state.examRun;if(!ex.sids.length||ex.simIdx>=ex.sids.length)return finishExam();let sim=SIMS.find(s=>s.id===ex.sids[ex.simIdx]);let saved=ex.simResponses[sim.id]||{text:'',checks:[]};$('app').innerHTML=`<div class="card"><div class="actions"><button onclick="exam()">Back to Exam Menu</button><button class="danger" onclick="discardExam()">Discard Exam</button></div><h2>Exam Mode — ${ex.label||'Exam'} Simulation ${ex.simIdx+1} of ${ex.sids.length}</h2><p class="muted">${sectionName(sim.sec)} · Exhibits open in a floating panel. You can continue typing while they remain open.</p><h3>${sim.title}</h3><p>${sim.prompt}</p><button onclick="openExhibits('${sim.id}')">Open Exhibits</button><h4>Tasks</h4><ol>${sim.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="exam-sim-${sim.id}" placeholder="Enter your simulation response here.">${saved.text||''}</textarea><div id="rubwrap-${sim.id}" style="display:none"><h4>Self-check items</h4>${sim.rubric.map((r,i)=>`<label><input type="checkbox" id="exam-${sim.id}-${i}" ${saved.checks?.[i]?'checked':''}> ${r}</label><br>`).join('')}<div id="rub-${sim.id}" class="muted"><ol>${sim.rubric.map(r=>`<li>${r}</li>`).join('')}</ol></div></div><div class="actions"><button onclick="saveExamSim('${sim.id}',false)">Save TBS Response</button><button id="rubbtn-${sim.id}" onclick="showRubric('${sim.id}')">Show Rubric</button><button class="primary" onclick="saveExamSim('${sim.id}',true)">${ex.simIdx+1===ex.sids.length?'Submit Exam':'Next Simulation'}</button></div></div>`}
function saveExamSim(id,advance){let ex=state.examRun;let sim=SIMS.find(s=>s.id===id);let checks=sim.rubric.map((_,i)=>$(`exam-${id}-${i}`).checked);ex.simResponses[id]={text:$(`exam-sim-${id}`).value,checks,date:new Date().toISOString(),sec:sim.sec,title:sim.title};state.sim[id]=ex.simResponses[id];logActivity('Exam TBS Saved',sim.sec,sim.title);if(advance)ex.simIdx++;save();examTbs();}
function finishExam(){let ex=state.examRun,total=ex.ids.length,responses=ex.responses||{},answeredCount=Object.keys(responses).length,score=Object.values(responses).filter(r=>r.correct).length,p=pct(score,total);let by={};ex.ids.forEach(id=>{let q=QUESTIONS.find(x=>x.id===id);by[q.sec]=by[q.sec]||{n:0,c:0};by[q.sec].n++;if(responses[id]?.correct)by[q.sec].c++;});let tbsDone=Object.keys(ex.simResponses||{}).length;let tbsList=ex.sids.map(id=>SIMS.find(s=>s.id===id)).filter(Boolean);state.examRun=null;logActivity('Exam Mode Submitted','mixed',`${p}% + ${tbsDone} TBS`);save();$('app').innerHTML=`<div class="card"><h2>Exam Submitted</h2><p class="metric">${p}%</p><p>${score} correct of ${total} MCQs. Responses recorded: ${answeredCount} of ${total}. Simulations completed: ${tbsDone} of ${ex.sids.length}.</p><h3>Performance by Area</h3><ul>${Object.entries(by).map(([k,v])=>`<li>${sectionName(k)}: ${pct(v.c,v.n)}%</li>`).join('')}</ul><h3>TBS Set</h3><ul>${tbsList.map(s=>`<li>${sectionName(s.sec)} — ${s.title}</li>`).join('')}</ul><button class="primary" onclick="state.view='Exam Mode';save();render()">Back to Exam Mode</button></div>`}
function systemHealth(){let checks=[['Unique question IDs',new Set(QUESTIONS.map(q=>q.id)).size===QUESTIONS.length],['At least 30 MCQs per area',SECTIONS.every(s=>areaQs(s.id).length>=30)],['Every question has four choices',QUESTIONS.every(q=>q.choices.length===4)],['Every answer key is A-D',QUESTIONS.every(q=>'ABCD'.includes(q.ans))],['Every question has metadata',QUESTIONS.every(q=>q.difficulty&&q.questionType&&q.sourceType&&q.topic&&q.sec)],['All flashcard decks have specific examples',FLASHCARDS.every(f=>f.back.includes('Example:')&&f.back.includes('CPA trap:'))],['All areas have at least 3 simulations',SECTIONS.every(s=>areaSims(s.id).length>=3)],['Expanded Full Exam Set available',QUESTIONS.length>=120&&SIMS.length>=12],['Progress backup available','Export + Import implemented'],['Calendar planner available',typeof calendar==='function'],['No hardcoded exam date',freshState().examDate===''],['Exam TBS exhibit window available',typeof openExhibits==='function'],['Individual exhibit selector available',typeof showExhibit==='function'],['Sample/Partial/Full Exam available',typeof startExam==='function'&&typeof resumeExam==='function'&&typeof discardExam==='function']];$('app').innerHTML=`<div class="card"><h2>System Health</h2><p class="muted">Student-facing status replacing internal QA checks.</p><table><tr><th>Check</th><th>Status</th></tr>${checks.map(c=>`<tr><td>${c[0]}</td><td>${c[1]===true?'PASS':c[1]===false?'REVIEW':c[1]}</td></tr>`).join('')}</table></div>`}
function backup(){$('app').innerHTML=`<div class="card"><h2>Backup & Restore</h2><p class="muted">Use this before installing a new release. On iPad, exported files are usually saved in Safari Downloads or Files > Downloads.</p><div class="actions"><button class="primary" onclick="exportProgress()">Export Progress</button><label><input type="file" accept="application/json,.json" onchange="importProgress(event)"> Import Progress</label><button class="danger" onclick="resetProgress()">Reset Progress</button></div><p class="muted">Expected export name: aud-v8-2-3-progress.json</p></div>`}
function toggleDark(){state.dark=!state.dark;localStorage.dark=state.dark?'1':'0';save();render()}
function exportProgress(){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='aud-v8-2-3-progress.json';a.click()}
function importProgress(evt){let file=evt.target.files[0];if(!file)return;let r=new FileReader();r.onload=()=>{try{let data=JSON.parse(r.result);if(!confirm('Import progress and replace current local progress?'))return;state={...freshState(),...data,version:APP_VERSION};if(state.examDate==='2026-08-31')state.examDate='';save();render();alert('Progress imported.')}catch(e){alert('Import failed: invalid progress file.')}};r.readAsText(file);}
function resetProgress(){if(confirm('Reset all local progress? Export first if you need a backup.')){state=freshState();save();render();}}
if('serviceWorker' in navigator){navigator.serviceWorker.register('./sw.js').catch(()=>{})}
render();
